Future<String> createOrOpenDirectChat(FriendUserData user) async {
  final firebaseUser = FirebaseAuth.instance.currentUser;

  if (firebaseUser == null) {
    throw FirebaseException(
      plugin: 'cloud_firestore',
      code: 'not-logged-in',
      message: 'Log in before opening chat.',
    );
  }

  if (user.uid.trim().isEmpty || user.uid == firebaseUser.uid) {
    throw FirebaseException(
      plugin: 'cloud_firestore',
      code: 'invalid-chat-user',
      message: 'This user profile is not available anymore.',
    );
  }

  if (await isUserBlockedByCurrentUser(user.uid)) {
    throw FirebaseException(
      plugin: 'cloud_firestore',
      code: 'blocked-user',
      message: 'You cannot message this user.',
    );
  }

  final chatId = directChatIdFor(firebaseUser.uid, user.uid);
  final memberIds = [firebaseUser.uid, user.uid];
  final memberUsernames = [currentUser.username, user.username];
  final memberPhotoUrls = [currentUser.photoUrl ?? '', user.photoUrl ?? ''];

  final chatRef = chatsCollection().doc(chatId);
  final existingChat = await chatRef.debugGet(
    null,
    'chat: direct open existing chat lookup',
  );

  if (existingChat.exists) {
    // Reopening a chat that this user hid should make it visible again. Avoid
    // refreshing other display fields here; older rules can reject that.
    final hiddenForUserIds = stringListFromFirebase(
      existingChat.data()?['hiddenForUserIds'],
      const [],
    );
    if (hiddenForUserIds.contains(firebaseUser.uid)) {
      try {
        await chatRef.debugSet(
          {
            'hiddenForUserIds': FieldValue.arrayRemove([firebaseUser.uid]),
          },
          SetOptions(merge: true),
          'chat: unhide direct chat on open',
        );
      } catch (error, stack) {
        debugPrint('Direct chat unhide skipped: $error');
        debugPrint('$stack');
      }
    }
    return chatId;
  } else {
    // New direct chats must include the same schema fields that the chat list
    // and Firestore rules expect. Omitting isGroup/lastMessage/createdAt can
    // make the create request fail with permission-denied, which surfaces in
    // the UI as "Could not open chat."
    await chatRef.debugSet({
      'isGroup': false,
      'name': '',
      'memberIds': memberIds,
      'memberUsernames': memberUsernames,
      'memberPhotoUrls': memberPhotoUrls,
      'photoUrl': '',
      'description': '',
      'lastMessage': '',
      'lastSenderUid': '',
      'lastSenderUsername': '',
      'ownerUid': '',
      'moderatorIds': [],
      'hiddenForUserIds': [],
      'updatedAt': FieldValue.serverTimestamp(),
      'createdAt': FieldValue.serverTimestamp(),
    });
  }

  return chatId;
}

Future<String> createGroupChat({
  required String name,
  required List<FriendUserData> users,
}) async {
  final firebaseUser = FirebaseAuth.instance.currentUser;

  if (firebaseUser == null) {
    throw FirebaseException(
      plugin: 'cloud_firestore',
      code: 'not-logged-in',
      message: 'Log in before creating chat.',
    );
  }

  final uniqueUsers = <String, FriendUserData>{
    for (final user in users) user.uid: user,
  }.values.toList();
  final memberIds = [firebaseUser.uid, ...uniqueUsers.map((user) => user.uid)];
  final memberUsernames = [
    currentUser.username,
    ...uniqueUsers.map((user) => user.username),
  ];
  final fallbackName = uniqueUsers
      .map((user) => user.username)
      .where((username) => username.trim().isNotEmpty)
      .take(3)
      .join(', ');
  final doc = chatsCollection().doc();

  await doc.debugSet({
    'isGroup': true,
    'name': name.trim().isEmpty ? fallbackName : name.trim(),
    'memberIds': memberIds,
    'memberUsernames': memberUsernames,
    'memberPhotoUrls': [
      currentUser.photoUrl ?? '',
      ...uniqueUsers.map((user) => user.photoUrl ?? ''),
    ],
    'ownerUid': firebaseUser.uid,
    'moderatorIds': [],
    'photoUrl': '',
    'description': '',
    'lastMessage': '',
    'lastSenderUid': '',
    'lastSenderUsername': '',
    'hiddenForUserIds': [],
    'updatedAt': FieldValue.serverTimestamp(),
    'createdAt': FieldValue.serverTimestamp(),
  });

  return doc.id;
}

Future<void> sendChatMessage({
  required String chatId,
  required String text,
  ChatThreadData? chat,
}) async {
  final firebaseUser = FirebaseAuth.instance.currentUser;

  if (firebaseUser == null) {
    throw FirebaseException(
      plugin: 'cloud_firestore',
      code: 'not-logged-in',
      message: 'Log in before sending messages.',
    );
  }

  final cleanText = text.trim();

  if (cleanText.isEmpty) {
    return;
  }

  // This is the only write that must succeed for the user-facing send action.
  // Other writes below are best-effort because some Firestore rules allow a
  // member to create messages but do not allow updating the parent chat summary
  // or creating notification documents. Those failures should not show "Could
  // not send message" after the message itself was accepted.
  final messageRef = await chatMessagesCollection(chatId).debugAdd({
    'senderUid': firebaseUser.uid,
    'senderUsername': currentUser.username,
    'text': cleanText,
    'createdAt': FieldValue.serverTimestamp(),
  });

  try {
    final chatMemberIds = chat?.memberIds
        .map((uid) => uid.trim())
        .where((uid) => uid.isNotEmpty)
        .toList();
    await chatsCollection().doc(chatId).debugSet({
      'lastMessage': cleanText,
      'lastSenderUid': firebaseUser.uid,
      'lastSenderUsername': currentUser.username,
      if (chatMemberIds != null && chatMemberIds.isNotEmpty)
        'hiddenForUserIds': FieldValue.arrayRemove(chatMemberIds),
      'updatedAt': FieldValue.serverTimestamp(),
    }, SetOptions(merge: true));
  } catch (error, stack) {
    debugPrint('Chat summary update skipped after message send: $error');
    debugPrint('$stack');
  }

  try {
    var notificationChat = chat;
    if (notificationChat == null) {
      try {
        final chatSnapshot = await chatsCollection().doc(chatId).debugGet();
        if (chatSnapshot.exists) {
          notificationChat = ChatThreadData.fromFirestore(chatSnapshot);
        }
      } catch (error) {
        debugPrint('Chat notification lookup skipped: $error');
      }
    }

    if (notificationChat != null) {
      await createChatMessageNotification(
        chat: notificationChat,
        messageText: cleanText,
      );
    }
  } catch (error, stack) {
    debugPrint('Chat notification creation skipped: $error');
    debugPrint('$stack');
  }

  await sendPushNotificationEvent({
    'type': 'chat_message',
    'chatId': chatId,
    'messageId': messageRef.id,
    'senderUsername': currentUser.username,
  });
}

Future<Position?> getChatSharePosition(BuildContext context) async {
  try {
    final serviceEnabled = await Geolocator.isLocationServiceEnabled();

    if (!serviceEnabled) {
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            backgroundColor: Colors.redAccent,
            content: Text(
              'Turn on phone location first.',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }

      return null;
    }

    var permission = await Geolocator.checkPermission();

    if (permission == LocationPermission.denied) {
      permission = await Geolocator.requestPermission();
    }

    if (permission == LocationPermission.denied ||
        permission == LocationPermission.deniedForever) {
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            backgroundColor: Colors.redAccent,
            content: Text(
              'Location permission is needed to share your location.',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }

      return null;
    }

    return Geolocator.getCurrentPosition(
      locationSettings: const LocationSettings(
        accuracy: LocationAccuracy.high,
        timeLimit: userLocationLookupTimeout,
      ),
    );
  } on TimeoutException {
    if (context.mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Could not find your location. Try again in a moment.',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
          ),
        ),
      );
    }

    return null;
  } catch (error) {
    if (context.mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Could not share location: $error',
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    }

    return null;
  }
}

String liveLocationDurationLabel(Duration duration) {
  final hours = duration.inHours;
  if (hours == 1) {
    return trText('1 hour');
  }

  return trText('$hours hours');
}

Future<bool> showLiveLocationSharingDisclaimer(BuildContext context) async {
  final prefs = await SharedPreferences.getInstance();
  final dismissed = prefs.getBool(liveLocationDisclaimerDismissedKey) == true;
  if (dismissed) {
    return true;
  }

  if (!context.mounted) {
    return false;
  }

  var doNotShowAgain = false;
  final accepted = await showDialog<bool>(
    context: context,
    barrierDismissible: false,
    builder: (dialogContext) {
      return StatefulBuilder(
        builder: (context, setDialogState) {
          return AlertDialog(
            backgroundColor: panelGlass,
            title: Text(
              trText('Share live location?'),
              style: const TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w900,
              ),
            ),
            content: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  trText(
                    'You are about to share your live location. People who have access to this share will be able to see you on the map until sharing expires or you stop it.',
                  ),
                  style: const TextStyle(color: Colors.white70, height: 1.35),
                ),
                const SizedBox(height: 14),
                InkWell(
                  borderRadius: BorderRadius.circular(12),
                  onTap: () =>
                      setDialogState(() => doNotShowAgain = !doNotShowAgain),
                  child: Row(
                    children: [
                      Checkbox(
                        value: doNotShowAgain,
                        activeColor: blue,
                        onChanged: (value) => setDialogState(
                          () => doNotShowAgain = value == true,
                        ),
                      ),
                      Expanded(
                        child: Text(
                          trText("Don't show again"),
                          style: const TextStyle(
                            color: Colors.white70,
                            fontWeight: FontWeight.w700,
                          ),
                        ),
                      ),
                    ],
                  ),
                ),
              ],
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.pop(dialogContext, false),
                child: Text(trText('Cancel')),
              ),
              ElevatedButton(
                onPressed: () => Navigator.pop(dialogContext, true),
                style: ElevatedButton.styleFrom(backgroundColor: blue),
                child: const Text('OK', style: TextStyle(color: Colors.white)),
              ),
            ],
          );
        },
      );
    },
  );

  if (accepted == true && doNotShowAgain) {
    await prefs.setBool(liveLocationDisclaimerDismissedKey, true);
  }

  return accepted == true;
}

Future<Duration?> showLiveLocationDurationDialog(BuildContext context) async {
  if (!context.mounted) {
    return null;
  }

  return showDialog<Duration>(
    context: context,
    barrierDismissible: true,
    builder: (dialogContext) {
      return AlertDialog(
        backgroundColor: panelGlass,
        title: Text(
          trText('Choose sharing duration'),
          style: const TextStyle(
            color: Colors.white,
            fontWeight: FontWeight.w900,
          ),
        ),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          children: liveLocationDurationChoices.map((duration) {
            final label = liveLocationDurationLabel(duration);
            return Padding(
