List<CarSpot> approvedPublicSpots() {
  // Public Explore/Map must show only real Firebase spots.
  // Demo spots stay in code as backup data, but they should not reappear
  // after an admin deletes an approved Firebase spot.
  return reviewSpots.value
      .where(
        (spot) =>
            spot.status == SpotStatus.approved &&
            spot.isVisibleNow &&
            (!spot.verifiedOnly || currentUserCanUseVerifiedOnlySpots),
      )
      .toList();
}

List<CarSpot> pendingReviewSpots() {
  return reviewSpots.value
      .where((spot) => spot.status == SpotStatus.pending)
      .toList();
}

bool isSameSpot(CarSpot first, CarSpot second) {
  if (first.id.isNotEmpty && second.id.isNotEmpty) {
    return first.id == second.id;
  }

  return first.name == second.name && first.addedBy == second.addedBy;
}

CarSpot spotWithCounterDelta(
  CarSpot spot, {
  int likeDelta = 0,
  int commentDelta = 0,
}) {
  return spot.copyWith(
    likeCount: math.max(0, spot.likeCount + likeDelta),
    commentCount: math.max(0, spot.commentCount + commentDelta),
    updatedAtMillis: DateTime.now().millisecondsSinceEpoch,
  );
}

void updateSpotLocally(CarSpot spot, CarSpot Function(CarSpot current) update) {
  var updatedSpotSources = false;

  for (final sourceEntry in _firebaseSpotCacheBySource.entries.toList()) {
    var sourceChanged = false;
    final nextSource = <String, CarSpot>{};

    for (final spotEntry in sourceEntry.value.entries) {
      final shouldUpdate =
          spotEntry.key == _spotCacheKey(spot) ||
          isSameSpot(spotEntry.value, spot);
      nextSource[spotEntry.key] = shouldUpdate
          ? update(spotEntry.value)
          : spotEntry.value;
      sourceChanged = sourceChanged || shouldUpdate;
    }

    if (sourceChanged) {
      _firebaseSpotCacheBySource[sourceEntry.key] = nextSource;
      updatedSpotSources = true;
    }
  }

  if (updatedSpotSources) {
    _publishFirebaseSpotCaches();
    unawaited(saveApprovedSpotsToLocalCache());
    return;
  }

  reviewSpots.value = reviewSpots.value
      .map((item) => isSameSpot(item, spot) ? update(item) : item)
      .toList();
  submittedSpots.value = submittedSpots.value
      .map((item) => isSameSpot(item, spot) ? update(item) : item)
      .toList();
  savedSpots.value = savedSpots.value
      .map((item) => isSameSpot(item, spot) ? update(item) : item)
      .toList();
}

void updateSpotCountersLocally(
  CarSpot spot, {
  int likeDelta = 0,
  int commentDelta = 0,
}) {
  if (likeDelta == 0 && commentDelta == 0) {
    return;
  }

  updateSpotLocally(
    spot,
    (current) => spotWithCounterDelta(
      current,
      likeDelta: likeDelta,
      commentDelta: commentDelta,
    ),
  );
}

Future<void> updateSpotCountersOnServer(
  CarSpot spot, {
  int likeDelta = 0,
  int commentDelta = 0,
}) async {
  final spotId = spot.id.trim();
  if (spotId.isEmpty || (likeDelta == 0 && commentDelta == 0)) {
    return;
  }

  final spotRef = spotsCollection().doc(spotId);

  try {
    await FirebaseFirestore.instance.runTransaction((transaction) async {
      final snapshot = await transaction.debugGet(
        spotRef,
        'spot counter safe current spot get',
      );
      if (!snapshot.exists) {
        return;
      }

      final data = snapshot.data() ?? const <String, dynamic>{};
      final update = <Object, Object?>{
        'updatedAt': FieldValue.serverTimestamp(),
      };

      if (likeDelta != 0) {
        final currentLikeCount = math.max(
          0,
          intFromFirebase(data['likeCount'], spot.likeCount),
        );
        update['likeCount'] = math.max(0, currentLikeCount + likeDelta);
      }

      if (commentDelta != 0) {
        final currentCommentCount = math.max(
          0,
          intFromFirebase(data['commentCount'], spot.commentCount),
        );
        update['commentCount'] = math.max(
          0,
          currentCommentCount + commentDelta,
        );
      }

      transaction.debugUpdate(spotRef, update, 'spot counter safe update');
    });
  } catch (error, stack) {
    debugPrint('Spot counter update failed for $spotId: $error');
    debugPrint('$stack');
  }
}

Future<void> updateSpotStatus(
  CarSpot spot,
  SpotStatus status, {
  String rejectionReason = '',
}) async {
  final statusChanged = spot.status != status;
  final cleanRejectionReason = status == SpotStatus.rejected
      ? rejectionReason.trim()
      : '';
  final shouldNotifyNearbyMeetUsers =
      status == SpotStatus.approved &&
      spot.status != SpotStatus.approved &&
      spot.categories.contains('Meet');
  final shouldNotifyOtherAdmins =
      statusChanged &&
      (status == SpotStatus.approved || status == SpotStatus.rejected);

  final updatedSpot = spot.copyWith(
    status: status,
    rating: status == SpotStatus.approved && spot.rating == 0
        ? 4.5
        : spot.rating,
    rejectionReason: cleanRejectionReason,
  );

  if (spot.id.isNotEmpty) {
    await spotsCollection().doc(spot.id).debugUpdate({
      'status': spotStatusName(status),
      'rating': updatedSpot.rating,
      'reviewedBy': currentUser.username,
      'reviewedByUid': currentUser.uid,
      'reviewedAt': FieldValue.serverTimestamp(),
      'rejectionReason': cleanRejectionReason,
      'updatedAt': FieldValue.serverTimestamp(),
    });
  }

  // Keep the local UI responsive while Firestore sends the fresh snapshot.
  reviewSpots.value = reviewSpots.value
      .map((item) => isSameSpot(item, spot) ? updatedSpot : item)
      .toList();
  submittedSpots.value = submittedSpots.value
      .map((item) => isSameSpot(item, spot) ? updatedSpot : item)
      .toList();
  savedSpots.value = savedSpots.value
      .map((item) => isSameSpot(item, spot) ? updatedSpot : item)
      .toList();

  upsertSpotIntoLocalImmediateCache(
    updatedSpot.copyWith(
      updatedAtMillis: DateTime.now().millisecondsSinceEpoch,
    ),
  );

  if (shouldNotifyNearbyMeetUsers) {
    await createMeetSpotNotificationsForNearbyUsers(updatedSpot);
  }

  if (shouldNotifyOtherAdmins) {
    await createAdminSpotDecisionNotification(
      updatedSpot,
      status,
      rejectionReason: cleanRejectionReason,
    );
  }

  if (statusChanged &&
      (status == SpotStatus.approved || status == SpotStatus.rejected)) {
    await createSpotReviewUpdateNotification(
      updatedSpot,
      status,
      rejectionReason: cleanRejectionReason,
    );
  }

  if (statusChanged &&
      spot.id.isNotEmpty &&
      (status == SpotStatus.approved || status == SpotStatus.rejected)) {
    await sendPushNotificationEvent({
      'type': 'spot_decision',
      'spotId': spot.id,
      'status': spotStatusName(status),
      if (cleanRejectionReason.isNotEmpty)
        'rejectionReason': cleanRejectionReason,
    });
  }
}

Future<void> deleteSpotFromFirebase(CarSpot spot) async {
  if (spot.id.isNotEmpty) {
    await spotsCollection().doc(spot.id).debugDelete();
  }

  removeSpotFromLocalImmediateCache(spot);

  reviewSpots.value = reviewSpots.value
      .where((item) => !isSameSpot(item, spot))
      .toList();
  submittedSpots.value = submittedSpots.value
      .where((item) => !isSameSpot(item, spot))
      .toList();
  savedSpots.value = savedSpots.value
      .where((item) => !isSameSpot(item, spot))
      .toList();
  unawaited(saveSavedSpotIds());
}

class SplashScreen extends StatefulWidget {
  const SplashScreen({super.key});

  @override
  State<SplashScreen> createState() => _SplashScreenState();
}

class _SplashScreenState extends State<SplashScreen>
    with SingleTickerProviderStateMixin {
  late final AnimationController introController;
  late final Animation<double> ccsSlide;
  late final Animation<double> subtitleSlide;
  late final Animation<double> taglineSlide;
  late final Animation<double> buttonSlide;
  late final Animation<double> ccsFade;
  late final Animation<double> subtitleFade;
  late final Animation<double> taglineFade;
  late final Animation<double> buttonFade;

  @override
  void initState() {
    super.initState();

    introController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1450),
    );

    ccsSlide = _slideAnimation(0.00, 0.58);
    subtitleSlide = _slideAnimation(0.14, 0.68);
    taglineSlide = _slideAnimation(0.28, 0.78);
    buttonSlide = _slideAnimation(0.44, 1.00);
    ccsFade = _fadeAnimation(0.00, 0.42);
    subtitleFade = _fadeAnimation(0.14, 0.52);
    taglineFade = _fadeAnimation(0.28, 0.66);
    buttonFade = _fadeAnimation(0.44, 0.88);

    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) {
        introController.forward();
      }
    });
  }

  Animation<double> _slideAnimation(double begin, double end) {
    return CurvedAnimation(
      parent: introController,
      curve: Interval(begin, end, curve: Curves.easeOutCubic),
    );
  }

  Animation<double> _fadeAnimation(double begin, double end) {
    return CurvedAnimation(
      parent: introController,
      curve: Interval(begin, end, curve: Curves.easeOut),
    );
  }

  @override
  void dispose() {
    introController.dispose();
    super.dispose();
  }

  void openLogin() {
    Navigator.push(
      context,
      PageRouteBuilder(
        transitionDuration: const Duration(milliseconds: 650),
        reverseTransitionDuration: const Duration(milliseconds: 450),
        pageBuilder: (context, animation, secondaryAnimation) {
          return const LoginScreen(showBackground: false);
        },
        transitionsBuilder: (context, animation, secondaryAnimation, child) {
          final curvedAnimation = CurvedAnimation(
            parent: animation,
            curve: Curves.easeOutCubic,
            reverseCurve: Curves.easeInCubic,
          );

          return Stack(
            fit: StackFit.expand,
            children: [
              Image.asset('assets/bg.png', fit: BoxFit.cover),
              Container(color: Colors.black.withValues(alpha: 0.42)),
              SlideTransition(
                position: Tween<Offset>(
                  begin: const Offset(0, 1),
                  end: Offset.zero,
                ).animate(curvedAnimation),
                child: FadeTransition(opacity: curvedAnimation, child: child),
              ),
            ],
          );
        },
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.black,
      body: Stack(
        fit: StackFit.expand,
        children: [
          Image.asset('assets/bg.png', fit: BoxFit.cover),
          Container(color: Colors.black.withValues(alpha: 0.42)),
          SafeArea(
            child: Padding(
              padding: const EdgeInsets.symmetric(horizontal: 28),
              child: Stack(
                children: [
                  Align(
                    alignment: const Alignment(0, -0.62),
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        _SplashIntroItem(
                          animation: ccsSlide,
                          fadeAnimation: ccsFade,
                          travel: 118,
                          child: const _CcsWordmark(),
                        ),
                        const SizedBox(height: 16),
                        _SplashIntroItem(
                          animation: subtitleSlide,
                          fadeAnimation: subtitleFade,
                          travel: 104,
                          child: const Text(
                            'COMMUNITY CAR SPOTS',
                            textAlign: TextAlign.center,
                            style: TextStyle(
                              fontSize: 17,
                              letterSpacing: 4.2,
                              color: Colors.white70,
                              fontWeight: FontWeight.w600,
                            ),
                          ),
                        ),
                        const SizedBox(height: 28),
                        _SplashIntroItem(
                          animation: taglineSlide,
                          fadeAnimation: taglineFade,
                          travel: 90,
                          child: const Text(
                            'FIND - DRIVE - SHOOT',
                            textAlign: TextAlign.center,
                            style: TextStyle(
                              fontSize: 13,
                              letterSpacing: 4.4,
                              color: Colors.white54,
                              fontWeight: FontWeight.w500,
                            ),
                          ),
                        ),
                      ],
                    ),
                  ),
                  Align(
                    alignment: const Alignment(0, 0.76),
                    child: Padding(
                      padding: const EdgeInsets.only(bottom: 8),
                      child: _SplashIntroItem(
                        animation: buttonSlide,
                        fadeAnimation: buttonFade,
                        travel: 78,
                        child: ElevatedButton(
                          onPressed: openLogin,
                          style: ElevatedButton.styleFrom(
                            backgroundColor: blue,
                            padding: const EdgeInsets.symmetric(
                              horizontal: 42,
                              vertical: 16,
                            ),
                            elevation: 12,
                            shadowColor: blue.withValues(alpha: 0.35),
                            shape: RoundedRectangleBorder(
                              borderRadius: BorderRadius.circular(18),
                            ),
                          ),
                          child: const Text(
                            'ENTER CCS',
                            style: TextStyle(
                              fontSize: 16,
                              letterSpacing: 2,
                              color: Colors.white,
                              fontWeight: FontWeight.w800,
                            ),
