class NotificationCenterItem {
  final String id;
  final String title;
  final String body;
  final String type;
  final int createdAtMillis;
  final bool read;
  final DocumentReference<Map<String, dynamic>>? reference;
  final bool projectNews;
  final String spotId;
  final String spotName;
  final String chatId;
  final String userId;
  final String addedByUid;
  final String actorUserId;
  final String actorUsername;
  final String status;
  final String rejectionReason;

  const NotificationCenterItem({
    required this.id,
    required this.title,
    required this.body,
    required this.type,
    required this.createdAtMillis,
    required this.read,
    this.reference,
    this.projectNews = false,
    this.spotId = '',
    this.spotName = '',
    this.chatId = '',
    this.userId = '',
    this.addedByUid = '',
    this.actorUserId = '',
    this.actorUsername = '',
    this.status = '',
    this.rejectionReason = '',
  });

  NotificationCenterItem copyWith({
    String? id,
    String? title,
    String? body,
    String? type,
    int? createdAtMillis,
    bool? read,
    DocumentReference<Map<String, dynamic>>? reference,
    bool clearReference = false,
    bool? projectNews,
    String? spotId,
    String? spotName,
    String? chatId,
    String? userId,
    String? addedByUid,
    String? actorUserId,
    String? actorUsername,
    String? status,
    String? rejectionReason,
  }) {
    return NotificationCenterItem(
      id: id ?? this.id,
      title: title ?? this.title,
      body: body ?? this.body,
      type: type ?? this.type,
      createdAtMillis: createdAtMillis ?? this.createdAtMillis,
      read: read ?? this.read,
      reference: clearReference ? null : (reference ?? this.reference),
      projectNews: projectNews ?? this.projectNews,
      spotId: spotId ?? this.spotId,
      spotName: spotName ?? this.spotName,
      chatId: chatId ?? this.chatId,
      userId: userId ?? this.userId,
      addedByUid: addedByUid ?? this.addedByUid,
      actorUserId: actorUserId ?? this.actorUserId,
      actorUsername: actorUsername ?? this.actorUsername,
      status: status ?? this.status,
      rejectionReason: rejectionReason ?? this.rejectionReason,
    );
  }

  bool get canOpen =>
      !projectNews &&
      (spotId.trim().isNotEmpty ||
          chatId.trim().isNotEmpty ||
          (type == 'chat_message' &&
              (actorUserId.trim().isNotEmpty ||
                  id.trim().startsWith('chat_'))) ||
          addedByUid.trim().isNotEmpty ||
          userId.trim().isNotEmpty ||
          type == 'friend_request' ||
          type == 'spot_pending_review');
}

bool notificationCenterItemIsRejected(NotificationCenterItem item) {
  final status = item.status.trim().toLowerCase();
  final title = item.title.trim().toLowerCase();
  final body = item.body.trim().toLowerCase();
  final type = item.type.trim().toLowerCase();

  return status == 'rejected' ||
      status.contains('reject') ||
      type == 'spot_rejected_by_admin' ||
      type.contains('reject') ||
      title.contains('rejected') ||
      title.contains('not approved') ||
      body.contains('rejected') ||
      body.contains('was rejected') ||
      body.contains('not approved') ||
      item.rejectionReason.trim().isNotEmpty;
}

String bodyWithRejectionReason(String body, String reason) {
  final cleanReason = reason.trim();
  if (cleanReason.isEmpty || body.toLowerCase().contains('reason:')) {
    return body;
  }

  final cleanBody = body.trim();
  if (cleanBody.isEmpty) {
    return 'Your spot was rejected. Reason: $cleanReason';
  }

  return '$cleanBody Reason: $cleanReason';
}

IconData notificationCenterIcon(NotificationCenterItem item) {
  if (item.projectNews) {
    return Icons.campaign;
  }

  // Rejection must always win over any generic review/update type. Some
  // notification payloads arrive as spot_review_update, so deciding only from
  // the type can incorrectly show the green approval check.
  if (notificationCenterItemIsRejected(item)) {
    return Icons.cancel;
  }

  return switch (item.type) {
    'spot_like' => Icons.favorite,
    'spot_comment' => Icons.chat_bubble,
    'chat_message' => Icons.mark_chat_unread,
    'spot_review_update' =>
      notificationCenterItemIsRejected(item)
          ? Icons.cancel
          : Icons.check_circle,
    'spot_pending_review' => Icons.fact_check,
    'spot_approved_by_admin' => Icons.check_circle,
    'spot_rejected_by_admin' => Icons.cancel,
    'new_spot' => Icons.add_location_alt,
    'temporary_event' => Icons.event_available,
    'friend_request' => Icons.person_add_alt_1,
    'friend_nearby' || 'friend_at_spot' => Icons.location_on,
    _ => Icons.notifications,
  };
}

Color notificationCenterColor(NotificationCenterItem item) {
  if (item.projectNews) {
    return const Color(0xFFFFB300);
  }

  // Same rule as the icon: any rejected review notification is red.
  if (notificationCenterItemIsRejected(item)) {
    return Colors.redAccent;
  }

  return switch (item.type) {
    'spot_like' => Colors.redAccent,
    'spot_comment' || 'chat_message' => blue,
    'spot_review_update' =>
      notificationCenterItemIsRejected(item) ? Colors.redAccent : Colors.green,
    'spot_rejected_by_admin' => Colors.redAccent,
    'spot_approved_by_admin' => Colors.green,
    'spot_pending_review' => blue,
    'new_spot' => const Color(0xFF9B35FF),
    'temporary_event' => const Color(0xFFFF7A00),
    'friend_request' => blue,
    'friend_nearby' || 'friend_at_spot' => Colors.greenAccent.shade700,
    _ => blue,
  };
}

String notificationCenterTime(int createdAtMillis) {
  if (createdAtMillis <= 0) {
    return '';
  }

  final time = DateTime.fromMillisecondsSinceEpoch(createdAtMillis);
  final now = DateTime.now();
  final difference = now.difference(time);

  if (difference.inMinutes < 1) {
    return trText('Just now');
  }

  if (difference.inHours < 1) {
    return '${difference.inMinutes} min';
  }

  if (difference.inDays < 1) {
    return '${difference.inHours} h';
  }

  final day = time.day.toString().padLeft(2, '0');
  final month = time.month.toString().padLeft(2, '0');
  return '$day.$month.${time.year}';
}

String actorUsernameFromNotificationBody(String body) {
  final match = RegExp(r'^@([^:\s]+):').firstMatch(body.trim());
  return match?.group(1)?.trim() ?? '';
}

String chatNotificationTitle(String actorUsername) {
  final cleanUsername = actorUsername.trim().replaceAll('@', '');
  return cleanUsername.isEmpty ? 'Messages' : 'Message from @$cleanUsername';
}

String notificationCenterDisplayTitle(NotificationCenterItem item) {
  if (item.type == 'chat_message') {
    return chatNotificationTitle(item.actorUsername);
  }

  return item.title;
}

String notificationCenterDisplayBody(NotificationCenterItem item) {
  final body = item.body.trim();
  if (item.type != 'chat_message') {
    if (notificationCenterItemIsRejected(item) &&
        item.rejectionReason.trim().isNotEmpty &&
        !body.toLowerCase().contains('reason:')) {
      final spotName = item.spotName.trim().isEmpty
          ? 'Your spot'
          : item.spotName.trim();
      return '$spotName was rejected. Reason: ${item.rejectionReason.trim()}';
    }
    return body;
  }

  final messageMatch = RegExp(r'^@[^:]+:\s*(.+)$').firstMatch(body);
  return messageMatch?.group(1)?.trim() ?? body;
}

String spotNameFromNotificationBody(String type, String body) {
  final cleanType = type.trim();
  final cleanBody = body.trim();
  if (cleanBody.isEmpty) {
    return '';
  }

  if (cleanType == 'spot_like') {
    final match = RegExp(
      r'\bliked\s+(.+?)\.?$',
      caseSensitive: false,
    ).firstMatch(cleanBody);
    return match?.group(1)?.trim().replaceAll(RegExp(r'\.+$'), '') ?? '';
  }

  if (cleanType == 'spot_comment') {
    final match = RegExp(
      r'\bcommented\s+on\s+(.+?)(?::|\.)?$',
      caseSensitive: false,
    ).firstMatch(cleanBody);
    return match?.group(1)?.trim().replaceAll(RegExp(r'\.+$'), '') ?? '';
  }

  if (cleanType == 'new_spot' || cleanType == 'temporary_event') {
    final patterns = [
      RegExp(
        r'^(.+?)\s+(?:event\s+)?was\s+added(?:\s+in\s+.+)?\.?$',
        caseSensitive: false,
      ),
      RegExp(
        r'^(.+?)\s+(?:event\s+)?(?:was\s+)?added(?:\s+in\s+.+)?\.?$',
        caseSensitive: false,
      ),
    ];

    for (final pattern in patterns) {
      final match = pattern.firstMatch(cleanBody);
      final value = match?.group(1)?.trim().replaceAll(RegExp(r'\.+$'), '');
      if (value != null && value.isNotEmpty) {
        return value;
      }
    }
  }

  if (cleanType == 'spot_review_update' ||
      cleanType == 'spot_rejected_by_admin' ||
      cleanType == 'spot_approved_by_admin' ||
      cleanType == 'spot_pending_review') {
    final patterns = [
      RegExp(r'^(.+?)\s+was\s+not\s+approved\.?$', caseSensitive: false),
      RegExp(
        r'^(.+?)\s+was\s+rejected(?:\.|\s+Reason:|$)',
        caseSensitive: false,
      ),
      RegExp(r'^(.+?)\s+was\s+approved\.?$', caseSensitive: false),
      RegExp(r'^(.+?)\s+is\s+waiting\s+for\s+review\.?$', caseSensitive: false),
      RegExp(r'^(.+?)\s+rejected\b', caseSensitive: false),
      RegExp(r'^(.+?)\s+approved\b', caseSensitive: false),
    ];

    for (final pattern in patterns) {
      final match = pattern.firstMatch(cleanBody);
      final value = match?.group(1)?.trim().replaceAll(RegExp(r'\.+$'), '');
      if (value != null && value.isNotEmpty) {
        return value;
      }
    }
  }

  return '';
}

Future<void> markNotificationReadBestEffort(
  DocumentReference<Map<String, dynamic>> reference,
) async {
  try {
    await reference.debugSet({'read': true}, SetOptions(merge: true));
  } catch (error) {
    // Some rules do not allow clients to update notification documents. Opening
    // the notification must still work, so treat this as cosmetic only.
    debugPrint('Notification read mark skipped: $error');
  }
}

NotificationCenterItem notificationCenterItemFromJson(Object? value) {
  final data = mapFromFirebase(value);
  final payload = mapFromFirebase(data['data']);

  String pickString(String key, String fallback) {
    final topLevel = stringFromFirebase(data[key], '');
    if (topLevel.trim().isNotEmpty) {
      return topLevel;
    }
    return stringFromFirebase(payload[key], fallback);
  }

  int pickMillis(String key) {
    final topLevel = data[key];
    if (topLevel is num) {
      return topLevel.toInt();
    }
    final nested = payload[key];
    if (nested is num) {
      return nested.toInt();
    }
    return 0;
  }

  final type = pickString('type', 'notification');
  final status = pickString('status', '');
  final rawSpotName = pickString('spotName', '');
  final rejectionReason = pickString('rejectionReason', '');
  var body = pickString('body', '');
  final spotName = rawSpotName.trim().isNotEmpty
      ? rawSpotName
      : spotNameFromNotificationBody(type, body);
  final rawActorUsername = pickString(
    'actorUsername',
    pickString('senderUsername', pickString('fromUsername', '')),
  );
  final actorUsername = rawActorUsername.trim().isEmpty
      ? actorUsernameFromNotificationBody(body)
      : rawActorUsername;
  final actorUserId = pickString(
    'actorUserId',
    pickString(
      'senderUid',
      pickString('senderUserId', pickString('fromUid', '')),
    ),
  );

  if (type == 'spot_review_update' &&
      status == 'rejected' &&
      rejectionReason.trim().isNotEmpty &&
      !body.toLowerCase().contains('reason:')) {
    final lowerBody = body.toLowerCase();
    if (body.trim().isEmpty || lowerBody.contains('not approved')) {
      body = spotName.trim().isEmpty
          ? 'Your spot was rejected. Reason: ${rejectionReason.trim()}'
          : '$spotName was rejected. Reason: ${rejectionReason.trim()}';
    } else if (lowerBody.contains('rejected')) {
      body = bodyWithRejectionReason(body, rejectionReason);
    }
  }

  return NotificationCenterItem(
    id: pickString('id', ''),
    title: pickString('title', 'CCS'),
    body: body,
    type: type,
    createdAtMillis: pickMillis('createdAtMillis'),
    read: data['read'] == true || payload['read'] == true,
    projectNews: data['projectNews'] == true || payload['projectNews'] == true,
    spotId: pickString('spotId', ''),
    spotName: spotName,
    chatId: (() {
      final v = pickString('chatId', '');
      if (v.isNotEmpty) return v;
      return pickString('chat_id', '');
    })(),
    userId: pickString('userId', ''),
    addedByUid: pickString('addedByUid', ''),
    actorUserId: actorUserId,
    actorUsername: actorUsername,
    status: status,
    rejectionReason: rejectionReason,
  );
}

NotificationCenterItem notificationCenterItemFromDocument(
  DocumentSnapshot<Map<String, dynamic>> doc, {
  bool projectNews = false,
}) {
  final data = doc.data() ?? {};
  final type = stringFromFirebase(
    data['type'],
    projectNews ? 'project_news' : 'notification',
  );
  final rawSpotName = stringFromFirebase(data['spotName'], '');
  final status = stringFromFirebase(data['status'], '');
  final reviewedBy = stringFromFirebase(data['reviewedBy'], '');
  final rejectionReason = stringFromFirebase(data['rejectionReason'], '');
  final actorUsername = stringFromFirebase(
    data['actorUsername'],
    stringFromFirebase(data['senderUsername'], ''),
  );
  final actorUserId = stringFromFirebase(
    data['actorUserId'],
    stringFromFirebase(data['senderUid'], ''),
  );
  final comment = stringFromFirebase(data['comment'], '');
  final friendUsername = stringFromFirebase(data['friendUsername'], '');
  // Always use the canonical title for each type — ignore whatever Firebase stored.
  final title = switch (type) {
    'spot_like' => 'Likes on my spots',
    'spot_comment' => 'Comments',
    'spot_review_update' => 'Spot review updates',
    'chat_message' => chatNotificationTitle(actorUsername),
    'new_spot' => 'New spots',
    'temporary_event' => 'Temporary events',
    'spot_pending_review' => 'Spot review updates',
    'spot_approved_by_admin' ||
    'spot_rejected_by_admin' => 'Spot review updates',
    'friend_request' => 'New friend request',
    'friend_nearby' || 'friend_at_spot' => 'Live location',
    'project_news' => 'Project news',
    _ => stringFromFirebase(data['title'], 'CCS'),
  };
  var body = stringFromFirebase(data['body'], '');
  final spotName = rawSpotName.trim().isNotEmpty
      ? rawSpotName
      : spotNameFromNotificationBody(type, body);

  if (body.trim().isEmpty) {
    body = switch (type) {
      'spot_like' =>
        spotName.trim().isEmpty
            ? '${actorUsername.trim().isEmpty ? 'Someone' : '@$actorUsername'} liked your spot.'
            : '${actorUsername.trim().isEmpty ? 'Someone' : '@$actorUsername'} liked $spotName.',
      'spot_comment' =>
        spotName.trim().isEmpty
            ? '${actorUsername.trim().isEmpty ? 'Someone' : '@$actorUsername'} commented on your spot${comment.trim().isEmpty ? '.' : ': $comment'}'
            : '${actorUsername.trim().isEmpty ? 'Someone' : '@$actorUsername'} commented on $spotName${comment.trim().isEmpty ? '.' : ': $comment'}',
      'chat_message' =>
        actorUsername.trim().isEmpty
            ? 'New message.'
            : '@$actorUsername: New message.',
      'new_spot' =>
        spotName.trim().isEmpty
            ? 'New spot was added.'
            : '$spotName was added.',
      'temporary_event' =>
        spotName.trim().isEmpty
            ? 'New temporary event was added.'
            : '$spotName temporary event was added.',
      'spot_review_update' =>
        status == 'approved'
            ? (spotName.trim().isEmpty
                  ? 'Your spot was approved.'
                  : '$spotName was approved.')
            : (spotName.trim().isEmpty
                  ? 'Your spot was rejected${rejectionReason.trim().isEmpty ? '.' : '. Reason: $rejectionReason'}'
                  : '$spotName was rejected${rejectionReason.trim().isEmpty ? '.' : '. Reason: $rejectionReason'}'),
      'spot_pending_review' =>
        spotName.trim().isEmpty
            ? 'New spot is waiting for review.'
            : '$spotName is waiting for review.',
      'spot_approved_by_admin' =>
        spotName.trim().isEmpty
            ? 'Spot approved.'
            : '$spotName approved${reviewedBy.trim().isEmpty ? '' : ' by $reviewedBy'}.',
      'spot_rejected_by_admin' =>
        spotName.trim().isEmpty
            ? 'Spot rejected${rejectionReason.trim().isEmpty ? '.' : '. Reason: $rejectionReason'}'
            : '$spotName rejected${reviewedBy.trim().isEmpty ? '' : ' by $reviewedBy'}${rejectionReason.trim().isEmpty ? '.' : '. Reason: $rejectionReason'}',
      'friend_request' =>
        friendUsername.trim().isEmpty
            ? 'Someone sent you a friend request.'
            : '@$friendUsername sent you a friend request.',
      'friend_nearby' =>
        friendUsername.trim().isEmpty
            ? 'A friend is nearby.'
            : '@$friendUsername is nearby.',
      'friend_at_spot' =>
        friendUsername.trim().isEmpty
            ? 'A friend is at a spot.'
            : '@$friendUsername is at ${spotName.trim().isEmpty ? 'a spot' : spotName}.',
      _ => stringFromFirebase(data['message'], ''),
    };
  }

  final cleanReason = rejectionReason.trim();
  final rejectedWithoutReason =
      cleanReason.isNotEmpty &&
      ((type == 'spot_review_update' && status == 'rejected') ||
          type == 'spot_rejected_by_admin') &&
      !body.toLowerCase().contains('reason:') &&
      body.toLowerCase().contains('rejected');
  if (rejectedWithoutReason) {
    body = bodyWithRejectionReason(body, cleanReason);
  }

  return NotificationCenterItem(
    id: doc.id,
    title: title,
    body: body,
    type: type,
    createdAtMillis: timestampMillisFromFirebase(data['createdAt']),
    read: data['read'] == true,
    reference: projectNews ? null : doc.reference,
    projectNews: projectNews,
    spotId: stringFromFirebase(data['spotId'], ''),
    spotName: spotName,
    chatId: (() {
      final v = stringFromFirebase(data['chatId'], '');
      if (v.isNotEmpty) return v;
      return stringFromFirebase(data['chat_id'], '');
    })(),
    userId: stringFromFirebase(data['userId'], ''),
    addedByUid: stringFromFirebase(data['addedByUid'], ''),
    actorUserId: actorUserId,
    actorUsername: actorUsername.trim().isEmpty
        ? actorUsernameFromNotificationBody(body)
        : actorUsername,
    status: status,
    rejectionReason: rejectionReason,
  );
}

String notificationCenterHiddenIdsKey(String uid) =>
    'notification_center_hidden_ids_$uid';

Future<Set<String>> loadHiddenNotificationCenterIds(String uid) async {
  try {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getStringList(notificationCenterHiddenIdsKey(uid))?.toSet() ??
        <String>{};
  } catch (_) {
    return <String>{};
  }
}

Future<void> saveHiddenNotificationCenterIds(
  String uid,
  Set<String> ids,
) async {
  try {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setStringList(
      notificationCenterHiddenIdsKey(uid),
      ids.toList(),
    );
  } catch (_) {}
}

Future<String> rejectionReasonForNotificationItem(
  NotificationCenterItem item,
) async {
  final existingReason = item.rejectionReason.trim();
  if (existingReason.isNotEmpty) {
    return existingReason;
  }

  final cleanSpotId = item.spotId.trim();
  if (cleanSpotId.isEmpty) {
    return '';
  }

  for (final spot in [
    ...reviewSpots.value,
    ...submittedSpots.value,
    ...approvedPublicSpots(),
  ]) {
    if (spot.id == cleanSpotId || spotReviewKey(spot) == cleanSpotId) {
      return spot.rejectionReason.trim();
    }
  }

  try {
    final doc = await spotsCollection().doc(cleanSpotId).debugGet();
    if (!doc.exists) {
      return '';
    }
    final data = doc.data() ?? {};
    return stringFromFirebase(data['rejectionReason'], '').trim();
  } catch (error, stack) {
    debugPrint('Could not load rejection reason for notification: $error');
    debugPrint('$stack');
    return '';
  }
}

Future<List<NotificationCenterItem>> enrichRejectedNotificationCenterItems(
  List<NotificationCenterItem> items,
) async {
  final enriched = <NotificationCenterItem>[];

  for (final item in items) {
    if (!notificationCenterItemIsRejected(item)) {
      enriched.add(item);
      continue;
    }

    final reason = await rejectionReasonForNotificationItem(item);
    if (reason.trim().isEmpty) {
      enriched.add(item);
      continue;
    }

    enriched.add(
      item.copyWith(
        status: item.status.trim().isEmpty ? 'rejected' : item.status,
        rejectionReason: reason.trim(),
        body: bodyWithRejectionReason(item.body, reason),
      ),
    );
  }

  return enriched;
}

String notificationCenterSpotDedupKey(NotificationCenterItem item) {
  final cleanName = item.spotName.trim().toLowerCase();
  if (cleanName.isNotEmpty) {
    return 'name:$cleanName';
  }

  final bodyName = spotNameFromNotificationBody(
    item.type,
    item.body,
  ).trim().toLowerCase();
  if (bodyName.isNotEmpty) {
    return 'name:$bodyName';
  }

  final cleanSpotId = item.spotId.trim();
  if (cleanSpotId.isNotEmpty) {
    return 'id:$cleanSpotId';
  }

  return '';
}

int rejectedNotificationStrength(NotificationCenterItem item) {
  final body = item.body.toLowerCase();
  var score = 1;

  if (body.contains('rejected')) {
    score = 2;
  }
  if (body.contains('reason:')) {
    score = 3;
  }
  if (item.rejectionReason.trim().isNotEmpty) {
    score = 4;
  }

  // Generic legacy wording is weaker than the explicit rejected notification,
  // even if we later enrich it with the rejection reason from the spot doc.
  if (body.contains('not approved')) {
    score -= 1;
  }

  return score;
}

List<NotificationCenterItem> removeDuplicateSpotReviewNotifications(
  List<NotificationCenterItem> items,
) {
  final strongestRejectedBySpot = <String, NotificationCenterItem>{};

  for (final item in items) {
    if (!notificationCenterItemIsRejected(item)) {
      continue;
    }

    final spotKey = notificationCenterSpotDedupKey(item);
    if (spotKey.isEmpty) {
      continue;
    }

    final existing = strongestRejectedBySpot[spotKey];
    if (existing == null ||
        rejectedNotificationStrength(item) >=
            rejectedNotificationStrength(existing)) {
      strongestRejectedBySpot[spotKey] = item;
    }
  }

  if (strongestRejectedBySpot.isEmpty) {
    return items;
  }

  return items.where((item) {
    if (!notificationCenterItemIsRejected(item)) {
      return true;
    }

    final spotKey = notificationCenterSpotDedupKey(item);
    if (spotKey.isEmpty) {
      return true;
    }

    final strongest = strongestRejectedBySpot[spotKey];
    if (strongest == null || identical(strongest, item)) {
      return true;
    }

    // Keep only the best rejected notification per spot. This removes the
    // older generic "was not approved" item when the proper rejected item
    // with a reason exists.
    return false;
  }).toList();
}

bool notificationCenterItemIsPublicSpot(NotificationCenterItem item) {
  return item.type == 'new_spot' || item.type == 'temporary_event';
}

String publicSpotNotificationDedupKey(NotificationCenterItem item) {
  final cleanName = item.spotName.trim().toLowerCase();
  if (cleanName.isNotEmpty) {
    return '${item.type}:name:$cleanName';
  }

  final bodyName = spotNameFromNotificationBody(
    item.type,
    item.body,
  ).trim().toLowerCase();
  if (bodyName.isNotEmpty) {
    return '${item.type}:name:$bodyName';
  }

  final cleanSpotId = item.spotId.trim();
  if (cleanSpotId.isNotEmpty) {
    return '${item.type}:id:$cleanSpotId';
  }

  return '';
}

int publicSpotNotificationStrength(NotificationCenterItem item) {
  var score = 0;
  if (item.spotId.trim().isNotEmpty) {
    score += 4;
  }
  if (item.spotName.trim().isNotEmpty) {
    score += 2;
  }

  // Backend-created public spot notifications are sent after the local write
  // and use the shorter body that opens correctly. Prefer them over the older
  // client-created duplicate that says "was added in ...".
  if (!item.body.toLowerCase().contains('was added in')) {
    score += 1;
  }

  if (item.reference == null) {
    score += 1;
  }

  return score;
}

List<NotificationCenterItem> removeDuplicatePublicSpotNotifications(
  List<NotificationCenterItem> items,
) {
  final strongestBySpot = <String, NotificationCenterItem>{};

  for (final item in items) {
    if (!notificationCenterItemIsPublicSpot(item)) {
      continue;
    }

    final spotKey = publicSpotNotificationDedupKey(item);
    if (spotKey.isEmpty) {
      continue;
    }

    final existing = strongestBySpot[spotKey];
    if (existing == null ||
        publicSpotNotificationStrength(item) >
            publicSpotNotificationStrength(existing) ||
        (publicSpotNotificationStrength(item) ==
                publicSpotNotificationStrength(existing) &&
            item.createdAtMillis >= existing.createdAtMillis)) {
      strongestBySpot[spotKey] = item;
    }
  }

  if (strongestBySpot.isEmpty) {
    return items;
  }

  return items.where((item) {
    if (!notificationCenterItemIsPublicSpot(item)) {
      return true;
    }

    final spotKey = publicSpotNotificationDedupKey(item);
    if (spotKey.isEmpty) {
      return true;
    }

    final strongest = strongestBySpot[spotKey];
    return strongest == null || identical(strongest, item);
  }).toList();
}

Future<Map<String, String>?> firebaseNotificationHeaders() async {
  final firebaseUser = FirebaseAuth.instance.currentUser;

  if (firebaseUser == null) {
    return null;
  }

  final token = await firebaseUser.getIdToken();
  if (token == null || token.trim().isEmpty) {
    return null;
  }

  return {HttpHeaders.authorizationHeader: 'Bearer $token'};
}

Future<QuerySnapshot<Map<String, dynamic>>> loadNotificationCenterSnapshot(
  CollectionReference<Map<String, dynamic>> collection,
  String uid,
  String label,
) async {
  final query = collection
      .where('userId', isEqualTo: uid)
      .orderBy('createdAt', descending: true)
      .limit(25);

  try {
    return await query.debugGet(null, 'notification center: $label');
  } catch (error, stack) {
    debugPrint(
      'Ordered notification query failed for $label, retrying without order: $error',
    );
    debugPrint('$stack');
    return collection
        .where('userId', isEqualTo: uid)
        .limit(25)
        .debugGet(null, 'notification center: $label fallback');
  }
}

Future<QuerySnapshot<Map<String, dynamic>>> loadUserNotificationCenterSnapshot(
  String uid,
) {
  return loadNotificationCenterSnapshot(
    userNotificationsCollection(),
    uid,
    'user notifications',
  );
}

Future<List<NotificationCenterItem>> loadNotificationCenterItems() async {
  final firebaseUser = FirebaseAuth.instance.currentUser;
  final items = <NotificationCenterItem>[];

  if (firebaseUser == null) {
    notificationCenterUnreadCountsBySource.clear();
    notificationCenterUnreadCountsBySource.clear();
    notificationCenterUnreadCount.value = 0;
    return const [];
  }

  Future<void> loadFromCollection(
    CollectionReference<Map<String, dynamic>> collection,
    String label,
  ) async {
    try {
      final snapshot = await loadNotificationCenterSnapshot(
        collection,
        firebaseUser.uid,
        label,
      );
      for (final doc in snapshot.docs) {
        items.add(notificationCenterItemFromDocument(doc));
      }
    } catch (error, stack) {
      debugPrint('Notification center could not load $label: $error');
      debugPrint('$stack');
    }
  }

  await loadFromCollection(userNotificationsCollection(), 'user notifications');
  await loadFromCollection(
    adminNotificationsCollection(),
    'admin notifications',
  );
  await loadFromCollection(
    friendLocationNotificationsCollection(),
    'friend location notifications',
  );

  final uniqueItemsById = <String, NotificationCenterItem>{};
  final uniqueItemsWithoutId = <NotificationCenterItem>[];
  for (final item in items) {
    final id = item.id.trim();
    if (id.isEmpty) {
      uniqueItemsWithoutId.add(item);
      continue;
    }

    final existing = uniqueItemsById[id];
    if (existing == null ||
        item.createdAtMillis >= existing.createdAtMillis ||
        item.reference?.path.startsWith('admin_notifications/') == true) {
      uniqueItemsById[id] = item;
    }
  }
  items
    ..clear()
    ..addAll(uniqueItemsById.values)
    ..addAll(uniqueItemsWithoutId);

  // User-facing action notifications need a real target. Old push/history
  // copies can have only title/body, which cannot open a chat or spot.
  items.removeWhere((item) {
    if (item.type == 'chat_message') {
      return chatIdFromNotificationItem(item).isEmpty;
    }

    if (item.type == 'spot_comment' || item.type == 'spot_like') {
      return item.reference == null &&
          item.spotId.trim().isEmpty &&
          spotNameFromNotificationBody(item.type, item.body).isEmpty;
    }

    return false;
  });

  if (!items.any((item) => item.projectNews)) {
    items.addAll(const [
      NotificationCenterItem(
        id: 'project_news_ready',
        title: 'Project news',
        body: 'CCS notification center is ready.',
        type: 'project_news',
        createdAtMillis: 0,
        read: true,
        projectNews: true,
      ),
    ]);
  }

  final hiddenIds = await loadHiddenNotificationCenterIds(firebaseUser.uid);
  if (hiddenIds.isNotEmpty) {
    items.removeWhere((item) {
      final id = item.id.trim();
      return id.isNotEmpty && hiddenIds.contains(id);
    });
  }

  final enrichedItems = removeDuplicatePublicSpotNotifications(
    removeDuplicateSpotReviewNotifications(
      await enrichRejectedNotificationCenterItems(items),
    ),
  );
  items
    ..clear()
    ..addAll(enrichedItems);

  items.sort((first, second) {
    if (first.createdAtMillis == second.createdAtMillis) {
      return first.projectNews ? 1 : -1;
    }

    return second.createdAtMillis.compareTo(first.createdAtMillis);
  });

  notificationCenterUnreadCount.value = items
      .where((item) => !item.read)
      .length;
  return items.take(25).toList();
}

Future<void> markNotificationCenterItemsRead(
  Iterable<NotificationCenterItem> items,
) async {
  final unreadItems = items.where((item) => !item.read).toList();
  final firestoreItems = unreadItems
      .where((item) => !item.read && item.reference != null)
      .toList();
  final serverNotificationIds = unreadItems
      .where((item) => item.reference == null && !item.projectNews)
      .map((item) => item.id.trim())
      .where((id) => id.isNotEmpty)
      .toSet()
      .toList();

  if (firestoreItems.isEmpty && serverNotificationIds.isEmpty) {
    return;
  }

  try {
    if (serverNotificationIds.isNotEmpty) {
      final headers = await firebaseNotificationHeaders();
      if (headers != null) {
        await patchJsonToUrl(pushNotificationUrl, {
          'notificationIds': serverNotificationIds,
        }, headers: headers);
      }
    }

    if (firestoreItems.isNotEmpty) {
      final batch = FirebaseFirestore.instance.batch();
      for (final item in firestoreItems) {
        final reference = item.reference;
        if (reference == null) {
          continue;
        }
        batch.debugSet(reference, {
          'read': true,
          'readAt': FieldValue.serverTimestamp(),
        }, SetOptions(merge: true));
      }
      await batch.commit();
    }

    notificationCenterUnreadCount.value = 0;
  } catch (error, stack) {
    debugPrint('Notification history could not be marked read: $error');
    debugPrint('$stack');
  }
}

Future<void> clearNotificationCenterItems(
  Iterable<NotificationCenterItem> items,
) async {
  final firebaseUser = FirebaseAuth.instance.currentUser;
  if (firebaseUser == null) {
    notificationCenterUnreadCountsBySource.clear();
    notificationCenterUnreadCount.value = 0;
    return;
  }

  final cleanItems = items.toList();
  if (cleanItems.isEmpty) {
    notificationCenterUnreadCountsBySource.clear();
    notificationCenterUnreadCount.value = 0;
    return;
  }

  final hiddenIds = await loadHiddenNotificationCenterIds(firebaseUser.uid);
  for (final item in cleanItems) {
    final id = item.id.trim();
    if (id.isNotEmpty) {
      hiddenIds.add(id);
    }
  }
  await saveHiddenNotificationCenterIds(firebaseUser.uid, hiddenIds);

  final references = cleanItems
      .map((item) => item.reference)
      .whereType<DocumentReference<Map<String, dynamic>>>()
      .toList();

  if (references.isNotEmpty) {
    try {
      final batch = FirebaseFirestore.instance.batch();
      for (final reference in references) {
        batch.debugDelete(reference);
      }
      await batch.commit();
    } catch (error, stack) {
      debugPrint('Notification center could not clear Firestore items: $error');
      debugPrint('$stack');
    }
  }

  final serverNotificationIds = cleanItems
      .where((item) => item.reference == null && !item.projectNews)
      .map((item) => item.id.trim())
      .where((id) => id.isNotEmpty)
      .toSet()
      .toList();

  if (serverNotificationIds.isNotEmpty) {
    try {
      final headers = await firebaseNotificationHeaders();
      if (headers != null) {
        // The backend currently supports marking notifications read. The local
        // hidden-id list above keeps cleared server-history items out of the
        // bell even if the backend does not physically delete them yet.
        await patchJsonToUrl(pushNotificationUrl, {
          'notificationIds': serverNotificationIds,
        }, headers: headers);
      }
    } catch (error, stack) {
      debugPrint(
        'Server notifications could not be marked read while clearing: $error',
      );
      debugPrint('$stack');
    }
  }

  notificationCenterUnreadCountsBySource.clear();
  notificationCenterUnreadCount.value = 0;
}

Future<void> refreshNotificationCenterUnreadCount() async {
  await loadNotificationCenterItems();
}

