class ExploreSpotStatsRow extends StatelessWidget {
  final CarSpot spot;
  final bool overlay;

  const ExploreSpotStatsRow({
    super.key,
    required this.spot,
    this.overlay = false,
  });

  Widget simpleStat({
    required IconData icon,
    required int count,
    required Color color,
    VoidCallback? onTap,
  }) {
    final content = Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        Icon(icon, color: color, size: overlay ? 16 : 18),
        const SizedBox(width: 5),
        Text(
          '$count',
          style: TextStyle(
            color: color,
            fontSize: overlay ? 12 : 13,
            fontWeight: FontWeight.w900,
            shadows: overlay
                ? const [Shadow(color: Colors.black, blurRadius: 5)]
                : null,
          ),
        ),
      ],
    );

    if (overlay) {
      return GestureDetector(
        behavior: HitTestBehavior.opaque,
        onTap: onTap,
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 3, vertical: 3),
          child: content,
        ),
      );
    }

    return InkWell(
      onTap: onTap,
      borderRadius: BorderRadius.circular(999),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
        decoration: BoxDecoration(
          color: color.withValues(alpha: 0.14),
          borderRadius: BorderRadius.circular(999),
          border: Border.all(color: color.withValues(alpha: 0.42)),
        ),
        child: content,
      ),
    );
  }

  Widget statsDivider() {
    if (overlay) {
      return const SizedBox(width: 5);
    }

    return const SizedBox(width: 7);
  }

  @override
  Widget build(BuildContext context) {
    final inactiveColor = overlay
        ? Colors.white.withValues(alpha: 0.88)
        : Colors.white70;

    return Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        StreamBuilder<bool>(
          stream: watchCurrentUserLikedSpot(spot),
          builder: (context, likedSnapshot) {
            final liked = likedSnapshot.data ?? false;

            return simpleStat(
              icon: liked ? Icons.favorite : Icons.favorite_border,
              count: spot.likeCount,
              color: liked ? Colors.redAccent : inactiveColor,
              onTap: () => toggleSpotLike(context, spot, liked),
            );
          },
        ),
        statsDivider(),
        simpleStat(
          icon: spot.commentCount > 0
              ? Icons.chat_bubble
              : Icons.chat_bubble_outline,
          count: spot.commentCount,
          color: inactiveColor,
          onTap: () => showSpotCommentComposer(context, spot),
        ),
      ],
    );
  }
}

Future<void> showSpotCommentComposer(BuildContext context, CarSpot spot) async {
  final messenger = ScaffoldMessenger.maybeOf(context);

  await showModalBottomSheet<void>(
    context: context,
    backgroundColor: panelGlass,
    isScrollControlled: true,
    useSafeArea: true,
    shape: const RoundedRectangleBorder(
      borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
    ),
    builder: (_) {
      return _SpotCommentComposerSheet(spot: spot, messenger: messenger);
    },
  );
}

class _SpotCommentComposerSheet extends StatefulWidget {
  final CarSpot spot;
  final ScaffoldMessengerState? messenger;

  const _SpotCommentComposerSheet({
    required this.spot,
    required this.messenger,
  });

  @override
  State<_SpotCommentComposerSheet> createState() =>
      _SpotCommentComposerSheetState();
}

class _SpotCommentComposerSheetState extends State<_SpotCommentComposerSheet> {
  late final TextEditingController controller;
  bool isSaving = false;

  @override
  void initState() {
    super.initState();
    controller = TextEditingController();
  }

  @override
  void dispose() {
    controller.dispose();
    super.dispose();
  }

  void showMessage(SnackBar snackBar) {
    final messenger = widget.messenger;
    if (messenger == null) {
      return;
    }

    messenger.clearSnackBars();
    messenger.showSnackBar(snackBar);
  }

  Future<void> submitComment() async {
    final comment = controller.text.trim();

    if (comment.isEmpty) {
      showMessage(
        const SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Write a comment first.',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
          ),
        ),
      );
      return;
    }

    if (isSaving) {
      return;
    }

    FocusManager.instance.primaryFocus?.unfocus();

    if (mounted) {
      setState(() => isSaving = true);
    }

    try {
      await saveSpotReview(spot: widget.spot, comment: comment);

      if (!mounted) {
        return;
      }

      Navigator.of(context).pop();

      WidgetsBinding.instance.addPostFrameCallback((_) {
        showMessage(
          const SnackBar(
            backgroundColor: blue,
            content: Text(
              'Comment posted.',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      });
    } catch (error) {
      if (!mounted) {
        return;
      }

      showMessage(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            spotReviewActionErrorMessage(
              error,
              fallback: 'Could not save comment.',
            ),
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );

      if (mounted) {
        setState(() => isSaving = false);
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final bottomInset = MediaQuery.viewInsetsOf(context).bottom;

    return SafeArea(
      top: false,
      child: AnimatedPadding(
        duration: const Duration(milliseconds: 180),
        curve: Curves.easeOutCubic,
        padding: EdgeInsets.fromLTRB(18, 14, 18, 18 + bottomInset),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Expanded(
                  child: Text(
                    'Comment ${widget.spot.name}',
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis,
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 20,
                      fontWeight: FontWeight.w900,
                    ),
                  ),
                ),
                IconButton(
                  onPressed: isSaving
                      ? null
                      : () {
                          FocusManager.instance.primaryFocus?.unfocus();
                          Navigator.of(context).pop();
                        },
                  icon: const Icon(Icons.close, color: Colors.white70),
                ),
              ],
            ),
            const SizedBox(height: 10),
            TextField(
              controller: controller,
              autofocus: false,
              minLines: 3,
              maxLines: 5,
              textInputAction: TextInputAction.newline,
              style: const TextStyle(color: Colors.white),
              decoration: InputDecoration(
                hintText: trText('Write a comment'),
                hintStyle: const TextStyle(color: Colors.white38),
                filled: true,
                fillColor: Colors.white.withValues(alpha: 0.06),
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(16),
                  borderSide: const BorderSide(color: Colors.white12),
                ),
                enabledBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(16),
                  borderSide: const BorderSide(color: Colors.white12),
                ),
                focusedBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(16),
                  borderSide: const BorderSide(color: blue),
                ),
              ),
            ),
            const SizedBox(height: 14),
            SizedBox(
              width: double.infinity,
              height: 50,
              child: ElevatedButton.icon(
                onPressed: isSaving ? null : submitComment,
                icon: Icon(isSaving ? Icons.hourglass_top : Icons.send),
                label: Text(isSaving ? 'Posting...' : 'Post Comment'),
                style: ElevatedButton.styleFrom(
                  backgroundColor: blue,
                  foregroundColor: Colors.white,
                  shape: RoundedRectangleBorder(
                    borderRadius: BorderRadius.circular(16),
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

