class SpotReviewsSection extends StatefulWidget {
  final CarSpot spot;

  const SpotReviewsSection({super.key, required this.spot});

  @override
  State<SpotReviewsSection> createState() => _SpotReviewsSectionState();
}

class _SpotReviewsSectionState extends State<SpotReviewsSection> {
  final commentController = TextEditingController();
  final List<SpotReviewData> reviews = [];
  DocumentSnapshot<Map<String, dynamic>>? lastReviewDocument;
  bool isSaving = false;
  bool isLoadingReviews = false;
  bool hasMoreReviews = true;
  bool useCommentsFallbackQuery = false;
  Object? reviewsError;

  @override
  void initState() {
    super.initState();
    if (!restoreReviewsFromSessionCache()) {
      unawaited(loadReviews(reset: true));
    }
  }

  @override
  void didUpdateWidget(SpotReviewsSection oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (spotReviewKey(oldWidget.spot) != spotReviewKey(widget.spot)) {
      reviews.clear();
      lastReviewDocument = null;
      hasMoreReviews = true;
      useCommentsFallbackQuery = false;
      reviewsError = null;
      if (!restoreReviewsFromSessionCache()) {
        unawaited(loadReviews(reset: true));
      }
    }
  }

  @override
  void dispose() {
    commentController.dispose();
    super.dispose();
  }

  bool restoreReviewsFromSessionCache() {
    final spotId = spotReviewKey(widget.spot);
    final cached = spotCommentsSessionCache[spotId];

    if (cached == null || !cached.isFresh) {
      return false;
    }

    reviews
      ..clear()
      ..addAll(cached.reviews);
    lastReviewDocument = cached.lastDocument;
    hasMoreReviews = cached.hasMoreReviews;
    useCommentsFallbackQuery = cached.useFallbackQuery;
    reviewsError = null;
    return true;
  }

  void saveReviewsToSessionCache() {
    final spotId = spotReviewKey(widget.spot);
    spotCommentsSessionCache[spotId] = SpotCommentsCacheEntry(
      reviews: List<SpotReviewData>.unmodifiable(reviews),
      lastDocument: lastReviewDocument,
      hasMoreReviews: hasMoreReviews,
      useFallbackQuery: useCommentsFallbackQuery,
      cachedAtMillis: DateTime.now().millisecondsSinceEpoch,
    );
  }

  Future<void> loadReviews({bool reset = false}) async {
    if (isLoadingReviews || (!reset && !hasMoreReviews)) {
      return;
    }

    if (mounted) {
      setState(() {
        isLoadingReviews = true;
        if (reset) {
          reviewsError = null;
        }
      });
    }

    Future<QuerySnapshot<Map<String, dynamic>>> loadSnapshot({
      required bool withTypeFilter,
      required String label,
    }) {
      Query<Map<String, dynamic>> query = spotReviewsCollection().where(
        'spotId',
        isEqualTo: spotReviewKey(widget.spot),
      );

      if (withTypeFilter) {
        query = query.where('type', isEqualTo: 'comment');
      }

      query = query.limit(
        withTypeFilter ? spotCommentsPageSize : spotCommentsPageSize * 3,
      );

      if (!reset && lastReviewDocument != null) {
        query = query.startAfterDocument(lastReviewDocument!);
      }

      return query.debugGet(null, label);
    }

    try {
      QuerySnapshot<Map<String, dynamic>> snapshot;
      var snapshotUsedFallback = useCommentsFallbackQuery;
      try {
        snapshot = await loadSnapshot(
          withTypeFilter: !useCommentsFallbackQuery,
          label: reset
              ? 'spot comments first page get'
              : 'spot comments next page get',
        );
      } on FirebaseException catch (error) {
        if (error.code != 'failed-precondition') {
          rethrow;
        }

        useCommentsFallbackQuery = true;
        snapshotUsedFallback = true;
        snapshot = await loadSnapshot(
          withTypeFilter: false,
          label: reset
              ? 'spot comments first page fallback get'
              : 'spot comments next page fallback get',
        );
      }

      final nextReviews = snapshot.docs
          .map((doc) => SpotReviewData.fromFirestore(doc))
          .where((review) => review.comment.trim().isNotEmpty)
          .take(spotCommentsPageSize)
          .toList();

      if (!mounted) {
        return;
      }

      setState(() {
        if (reset) {
          reviews.clear();
        }
        reviews.addAll(nextReviews);
        if (snapshot.docs.isNotEmpty) {
          lastReviewDocument = snapshot.docs.last;
        }
        hasMoreReviews =
            snapshot.docs.length ==
            (snapshotUsedFallback
                ? spotCommentsPageSize * 3
                : spotCommentsPageSize);
        reviewsError = null;
        isLoadingReviews = false;
      });
      saveReviewsToSessionCache();
    } catch (error) {
      if (!mounted) {
        return;
      }

      setState(() {
        reviewsError = error;
        isLoadingReviews = false;
      });
    }
  }

  Future<void> submitComment() async {
    final comment = commentController.text.trim();

    if (comment.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Write a comment first.',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
          ),
        ),
      );
      return;
    }

    if (isSaving) {
      return;
    }

    FocusManager.instance.primaryFocus?.unfocus();
    setState(() => isSaving = true);

    try {
      final review = await saveSpotReview(spot: widget.spot, comment: comment);

      if (!mounted) {
        return;
      }

      commentController.clear();
      setState(() {
        reviews.removeWhere((item) => item.id == review.id);
        reviews.insert(0, review);
      });
      saveReviewsToSessionCache();

      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          backgroundColor: blue,
          content: Text(
            'Comment posted.',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
          ),
        ),
      );
    } catch (error) {
      if (!mounted) {
        return;
      }

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            spotReviewActionErrorMessage(
              error,
              fallback: 'Could not save comment.',
            ),
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    } finally {
      if (mounted) {
        setState(() => isSaving = false);
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final visibleCommentCount = math.max(
      widget.spot.commentCount,
      reviews.length,
    );

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          children: [
            const Text(
              'Comments',
              style: TextStyle(
                color: Colors.white,
                fontSize: 20,
                fontWeight: FontWeight.w900,
              ),
            ),
            const Spacer(),
            Text(
              visibleCommentCount == 0
                  ? '0 comments'
                  : '$visibleCommentCount ${visibleCommentCount == 1 ? 'comment' : 'comments'}',
              style: const TextStyle(
                color: Colors.white70,
                fontWeight: FontWeight.w800,
              ),
            ),
          ],
        ),
        const SizedBox(height: 14),
        Container(
          width: double.infinity,
          padding: const EdgeInsets.all(14),
          decoration: BoxDecoration(
            color: panelGlass,
            borderRadius: BorderRadius.circular(18),
            border: Border.all(color: Colors.white12),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              TextField(
                controller: commentController,
                minLines: 2,
                maxLines: 4,
                style: const TextStyle(color: Colors.white),
                decoration: InputDecoration(
                  hintText: trText('Write a comment about this spot'),
                  hintStyle: const TextStyle(color: Colors.white38),
                  filled: true,
                  fillColor: Colors.white.withValues(alpha: 0.06),
                  border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(14),
                    borderSide: const BorderSide(color: Colors.white12),
                  ),
                  enabledBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(14),
                    borderSide: const BorderSide(color: Colors.white12),
                  ),
                  focusedBorder: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(14),
                    borderSide: const BorderSide(color: blue),
                  ),
                ),
              ),
              const SizedBox(height: 12),
              SizedBox(
                width: double.infinity,
                height: 46,
                child: ElevatedButton.icon(
                  onPressed: isSaving ? null : submitComment,
                  icon: Icon(isSaving ? Icons.hourglass_bottom : Icons.send),
                  label: Text(isSaving ? 'Saving...' : 'Post Comment'),
                  style: ElevatedButton.styleFrom(
                    backgroundColor: blue,
                    foregroundColor: Colors.white,
                    shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(15),
                    ),
                  ),
                ),
              ),
            ],
          ),
        ),
        const SizedBox(height: 14),
        if (reviewsError != null)
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(16),
            decoration: BoxDecoration(
              color: Colors.redAccent.withValues(alpha: 0.12),
              borderRadius: BorderRadius.circular(18),
              border: Border.all(
                color: Colors.redAccent.withValues(alpha: 0.5),
              ),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const Text(
                  'Could not load comments.',
                  style: TextStyle(
                    color: Colors.white,
                    fontWeight: FontWeight.w900,
                  ),
                ),
                const SizedBox(height: 8),
                Text(
                  '$reviewsError',
                  style: const TextStyle(color: Colors.white70),
                ),
                const SizedBox(height: 10),
                OutlinedButton.icon(
                  onPressed: () => loadReviews(reset: reviews.isEmpty),
                  icon: const Icon(Icons.refresh),
                  label: const Text('Retry'),
                ),
              ],
            ),
          )
        else if (reviews.isEmpty && isLoadingReviews)
          const Center(child: CircularProgressIndicator(color: blue))
        else if (reviews.isEmpty)
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(16),
            decoration: BoxDecoration(
              color: panelGlass,
              borderRadius: BorderRadius.circular(18),
              border: Border.all(color: Colors.white12),
            ),
            child: const Text(
              'No comments yet. Be the first to comment on this spot.',
              style: TextStyle(color: Colors.white54),
            ),
          )
        else
          for (final review in reviews) ...[
            SpotReviewCard(
              spot: widget.spot,
              review: review,
              onDeleted: () {
                setState(() {
                  reviews.removeWhere((item) => item.id == review.id);
                });
                removeSpotReviewFromSessionCache(
                  spotReviewKey(widget.spot),
                  review.id,
                );
                saveReviewsToSessionCache();
              },
            ),
            const SizedBox(height: 10),
          ],
        if (hasMoreReviews && reviews.isNotEmpty) ...[
          const SizedBox(height: 2),
          SizedBox(
            width: double.infinity,
            height: 44,
            child: OutlinedButton.icon(
              onPressed: isLoadingReviews
                  ? null
                  : () => unawaited(loadReviews()),
              icon: isLoadingReviews
                  ? const SizedBox(
                      width: 17,
                      height: 17,
                      child: CircularProgressIndicator(
                        strokeWidth: 2,
                        color: blue,
                      ),
                    )
                  : const Icon(Icons.expand_more),
              label: Text(isLoadingReviews ? 'Loading...' : 'More comments'),
              style: OutlinedButton.styleFrom(
                foregroundColor: blue,
                side: const BorderSide(color: blue),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(15),
                ),
              ),
            ),
          ),
        ],
      ],
    );
  }
}

class SpotReviewCard extends StatelessWidget {
  final CarSpot spot;
  final SpotReviewData review;
  final VoidCallback? onDeleted;

  const SpotReviewCard({
    super.key,
    required this.spot,
    required this.review,
    this.onDeleted,
  });

  Future<void> _showEditDialog(BuildContext context) async {
    final commentController = TextEditingController(text: review.comment);

    final saved = await showDialog<bool>(
      context: context,
      builder: (context) {
        return AlertDialog(
          backgroundColor: panelGlass,
          title: const Text(
            'Edit comment',
            style: TextStyle(color: Colors.white),
          ),
          content: StatefulBuilder(
            builder: (context, setState) {
              return Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  TextField(
                    controller: commentController,
                    minLines: 3,
                    maxLines: 5,
                    style: const TextStyle(color: Colors.white),
                    decoration: InputDecoration(
                      hintText: trText('Edit your comment'),
                      hintStyle: const TextStyle(color: Colors.white38),
                      filled: true,
                      fillColor: Colors.white.withValues(alpha: 0.06),
                      border: OutlineInputBorder(
                        borderRadius: BorderRadius.circular(14),
                        borderSide: const BorderSide(color: Colors.white12),
                      ),
                    ),
                  ),
                ],
              );
            },
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(context).pop(false),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              onPressed: () {
                if (commentController.text.trim().isEmpty) {
                  return;
                }
                Navigator.of(context).pop(true);
              },
              child: const Text('Save'),
            ),
          ],
        );
      },
    );

    if (saved != true) {
      return;
    }

    final newComment = commentController.text.trim();

    try {
      await editSpotReview(spot: spot, review: review, comment: newComment);
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            backgroundColor: blue,
            content: Text(
              'Comment updated.',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    } catch (error) {
      if (context.mounted) {
        final code = error is FirebaseException ? error.code : error.toString();
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            backgroundColor: Colors.redAccent,
            content: Text(
              'Could not update comment: $code',
              style: const TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    }
  }

  Future<void> _showDeleteDialog(BuildContext context) async {
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (context) {
        return AlertDialog(
          backgroundColor: panelGlass,
          title: const Text(
            'Delete comment',
            style: TextStyle(color: Colors.white),
          ),
          content: const Text(
            'Are you sure you want to delete this comment?',
            style: TextStyle(color: Colors.white70),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(context).pop(false),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              style: ElevatedButton.styleFrom(
                backgroundColor: Colors.redAccent,
              ),
              onPressed: () => Navigator.of(context).pop(true),
              child: const Text('Delete'),
            ),
          ],
        );
      },
    );

    if (confirmed != true) {
      return;
    }

    try {
      await deleteSpotReview(spot: spot, review: review);
      onDeleted?.call();
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            backgroundColor: blue,
            content: Text(
              'Comment deleted.',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    } catch (error) {
      if (context.mounted) {
        final code = error is FirebaseException ? error.code : error.toString();
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            backgroundColor: Colors.redAccent,
            content: Text(
              'Could not delete comment: $code',
              style: const TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final currentUid = FirebaseAuth.instance.currentUser?.uid;
    final canEdit = currentUid == review.userId;
    final canDelete = canEdit || userRoleIsAdmin(currentUser.role);

    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(14),
      decoration: BoxDecoration(
        color: panelGlass,
        borderRadius: BorderRadius.circular(18),
        border: Border.all(color: Colors.white12),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Expanded(
                child: InkWell(
                  onTap: review.userId.trim().isEmpty
                      ? null
                      : () => openUserProfile(
                          context,
                          uid: review.userId,
                          fallbackUsername: review.username,
                        ),
                  borderRadius: BorderRadius.circular(999),
                  child: Padding(
                    padding: const EdgeInsets.symmetric(vertical: 3),
                    child: Text(
                      displayUsername(review.username),
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                        color: blue,
                        fontWeight: FontWeight.w900,
                      ),
                    ),
                  ),
                ),
              ),
              Text(
                formatShortDate(review.createdAt),
                style: const TextStyle(color: Colors.white54, fontSize: 12),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Text(
            review.comment,
            style: const TextStyle(color: Colors.white70, height: 1.35),
          ),
          if (canEdit || canDelete) ...[
            const SizedBox(height: 10),
            Row(
              mainAxisAlignment: MainAxisAlignment.end,
              children: [
                if (canEdit)
                  IconButton(
                    onPressed: () => _showEditDialog(context),
                    icon: const Icon(
                      Icons.edit,
                      color: Colors.white54,
                      size: 18,
                    ),
                    tooltip: 'Edit comment',
                  ),
                if (canDelete)
                  IconButton(
                    onPressed: () => _showDeleteDialog(context),
                    icon: const Icon(
                      Icons.delete_outline,
                      color: Colors.white54,
                      size: 18,
                    ),
                    tooltip: 'Delete comment',
                  ),
              ],
            ),
          ],
        ],
      ),
    );
  }
}

class SpotPhoto extends StatelessWidget {
  final CarSpot spot;
  final double? width;
  final double? height;
  final BoxFit fit;
  final BorderRadius? borderRadius;

  const SpotPhoto({
    super.key,
    required this.spot,
    this.width,
    this.height,
    this.fit = BoxFit.cover,
    this.borderRadius,
  });

  @override
  Widget build(BuildContext context) {
    final sources = spotPhotoSources(spot);
    final photo = sources.isEmpty
        ? _SpotPhotoPlaceholder(width: width, height: height)
        : spotPhotoImage(sources.first, width: width, height: height, fit: fit);

    if (borderRadius == null) {
      return photo;
    }

    return ClipRRect(borderRadius: borderRadius!, child: photo);
  }
}

