const pinnedChatIdsPreferenceKey = 'pinned_chat_ids_v1';

Future<List<String>> loadPinnedChatIds() async {
  final prefs = await SharedPreferences.getInstance();
  return prefs.getStringList(pinnedChatIdsPreferenceKey) ?? <String>[];
}

Future<void> savePinnedChatIds(List<String> ids) async {
  final prefs = await SharedPreferences.getInstance();
  await prefs.setStringList(pinnedChatIdsPreferenceKey, ids.take(6).toList());
}

Future<void> removePinnedChatId(String chatId) async {
  final cleanChatId = chatId.trim();
  if (cleanChatId.isEmpty) {
    return;
  }

  final ids = await loadPinnedChatIds();
  ids.removeWhere((id) => id == cleanChatId);
  await savePinnedChatIds(ids);
}

Widget chatAvatarWidget(ChatThreadData chat, String currentUid) {
  final photoUrl = chat.directPhotoUrlForCurrentUser(currentUid);

  if (!chat.isGroup && isNetworkUrl(photoUrl)) {
    return ClipOval(
      child: Image.network(
        photoUrl,
        width: 46,
        height: 46,
        fit: BoxFit.cover,
        errorBuilder: (_, _, _) =>
            const Icon(Icons.person_outline, color: blue),
      ),
    );
  }

  if (chat.isGroup && isNetworkUrl(chat.avatarUrl)) {
    return ClipOval(
      child: Image.network(
        chat.avatarUrl,
        width: 46,
        height: 46,
        fit: BoxFit.cover,
        errorBuilder: (_, _, _) => const Icon(Icons.groups, color: blue),
      ),
    );
  }

  return Icon(chat.isGroup ? Icons.groups : Icons.person_outline, color: blue);
}

class ChatScreen extends StatefulWidget {
  const ChatScreen({super.key});

  @override
  State<ChatScreen> createState() => _ChatScreenState();
}

class _ChatScreenState extends State<ChatScreen> {
  List<String> pinnedChatIds = const [];
  bool showGroupsTab = false;

  @override
  void initState() {
    super.initState();
    loadPins();
  }

  Future<void> loadPins() async {
    final ids = await loadPinnedChatIds();
    if (mounted) {
      setState(() => pinnedChatIds = ids);
    }
  }

  Future<void> openNewChat(BuildContext context) async {
    await Navigator.push(
      context,
      appPageRoute(builder: (_) => const NewChatScreen()),
    );
    loadPins();
  }

  Future<void> openChatManager(
    BuildContext context,
    List<ChatThreadData> chats,
  ) async {
    await Navigator.push(
      context,
      appPageRoute(
        builder: (_) =>
            ChatManageScreen(chats: chats, currentPinnedIds: pinnedChatIds),
      ),
    );
    loadPins();
  }

  List<ChatThreadData> sortedChats(List<ChatThreadData> chats) {
    final pinnedSet = pinnedChatIds.toSet();
    chats.sort((a, b) {
      final aPinned = pinnedSet.contains(a.id);
      final bPinned = pinnedSet.contains(b.id);

      if (aPinned != bPinned) {
        return aPinned ? -1 : 1;
      }

      if (aPinned && bPinned) {
        return pinnedChatIds
            .indexOf(a.id)
            .compareTo(pinnedChatIds.indexOf(b.id));
      }

      return b.updatedAtMillis.compareTo(a.updatedAtMillis);
    });
    return chats;
  }

  Widget sectionTitle(String title, int count) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 10),
      child: Row(
        children: [
          Text(
            title,
            style: const TextStyle(
              color: Colors.white,
              fontSize: 20,
              fontWeight: FontWeight.w900,
            ),
          ),
          const SizedBox(width: 8),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
            decoration: BoxDecoration(
              color: blue.withValues(alpha: 0.16),
              borderRadius: BorderRadius.circular(999),
            ),
            child: Text(
              '$count',
              style: const TextStyle(
                color: blue,
                fontSize: 12,
                fontWeight: FontWeight.w900,
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget chatSection({
    required String title,
    required String emptyText,
    required List<ChatThreadData> chats,
    required String currentUid,
  }) {
    return Container(
      padding: const EdgeInsets.all(14),
      decoration: BoxDecoration(
        color: panel.withValues(alpha: 0.58),
        borderRadius: BorderRadius.circular(22),
        border: Border.all(color: Colors.white12),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          sectionTitle(title, chats.length),
          if (chats.isEmpty)
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 12),
              child: Text(
                emptyText,
                style: const TextStyle(color: Colors.white54, height: 1.35),
              ),
            )
          else
            for (final chat in chats) ...[
              ChatThreadTile(
                chat: chat,
                currentUid: currentUid,
                pinned: pinnedChatIds.contains(chat.id),
              ),
              const SizedBox(height: 10),
            ],
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final firebaseUser = FirebaseAuth.instance.currentUser;

    if (firebaseUser == null) {
      return Scaffold(
        backgroundColor: Colors.transparent,
        appBar: AppBar(
          title: const CcsAppBarLogo(),
          backgroundColor: Colors.transparent,
          foregroundColor: blue,
          actions: ccsAppBarActions(),
        ),
        body: const Padding(
          padding: EdgeInsets.fromLTRB(20, 18, 20, 28),
          child: EmptyStateCard(
            icon: Icons.chat_bubble_outline,
            title: 'Log in required',
            text: 'Log in before using chat.',
          ),
        ),
      );
    }

    return StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
      stream: currentUserChatsQuery(
        firebaseUser.uid,
      ).debugSnapshots('chat: threads list listener'),
      builder: (context, snapshot) {
        final chats =
            snapshot.data?.docs
                .map((doc) => ChatThreadData.fromFirestore(doc))
                .where((chat) => !chat.isHiddenFor(firebaseUser.uid))
                .toList() ??
            <ChatThreadData>[];
        final directChats = sortedChats(
          chats.where((chat) => !chat.isGroup).toList(),
        );
        final groupChats = sortedChats(
          chats.where((chat) => chat.isGroup).toList(),
        );

        final body = ListView(
          padding: const EdgeInsets.fromLTRB(20, 18, 20, 92),
          children: [
            Row(
              children: [
                const Expanded(
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        'Chat',
                        style: TextStyle(
                          color: Colors.white,
                          fontSize: 34,
                          fontWeight: FontWeight.w900,
                        ),
                      ),
                      SizedBox(height: 6),
                      Text(
                        'Messages with friends and groups',
                        style: TextStyle(color: Colors.white54, height: 1.35),
                      ),
                    ],
                  ),
                ),
                IconButton.filled(
                  onPressed: () => openNewChat(context),
                  style: IconButton.styleFrom(
                    backgroundColor: blue,
                    foregroundColor: Colors.white,
                  ),
                  icon: const Icon(Icons.add),
                ),
              ],
            ),
            const SizedBox(height: 18),
            SizedBox(
              width: double.infinity,
              child: SegmentedButton<bool>(
                segments: const [
                  ButtonSegment<bool>(
                    value: false,
                    icon: Icon(Icons.person_outline),
                    label: Text('Chats'),
                  ),
                  ButtonSegment<bool>(
                    value: true,
                    icon: Icon(Icons.groups),
                    label: Text('Groups'),
                  ),
                ],
                selected: {showGroupsTab},
                onSelectionChanged: (value) {
                  setState(() => showGroupsTab = value.first);
                },
                style: ButtonStyle(
                  foregroundColor: WidgetStateProperty.resolveWith(
                    (states) => states.contains(WidgetState.selected)
                        ? Colors.white
                        : Colors.white70,
                  ),
                  backgroundColor: WidgetStateProperty.resolveWith(
                    (states) =>
                        states.contains(WidgetState.selected) ? blue : panel,
                  ),
                ),
              ),
            ),
            const SizedBox(height: 18),
            if (snapshot.connectionState == ConnectionState.waiting)
              const Center(
                child: Padding(
                  padding: EdgeInsets.all(24),
                  child: CircularProgressIndicator(color: blue),
                ),
              )
            else if (chats.isEmpty)
              const EmptyStateCard(
                icon: Icons.chat_bubble_outline,
                title: 'No chats yet',
                text: 'Start a chat with a friend or create a group.',
              )
            else if (!showGroupsTab)
              chatSection(
                title: 'Chats',
                emptyText: 'No direct chats yet.',
                chats: directChats,
                currentUid: firebaseUser.uid,
              )
            else
              chatSection(
                title: 'Groups',
                emptyText: 'No groups yet.',
                chats: groupChats,
                currentUid: firebaseUser.uid,
              ),
          ],
        );

        return Scaffold(
          backgroundColor: Colors.transparent,
          appBar: AppBar(
            title: const CcsAppBarLogo(),
            backgroundColor: Colors.transparent,
            foregroundColor: blue,
            actions: ccsAppBarActions(),
          ),
          floatingActionButton: FloatingActionButton(
            onPressed: () => openChatManager(context, chats),
            backgroundColor: blue,
            foregroundColor: Colors.white,
            child: const Icon(Icons.tune),
          ),
          body: body,
        );
      },
    );
  }
}

bool currentUserCanDeleteGroupChat(ChatThreadData chat) {
  final uid = FirebaseAuth.instance.currentUser?.uid ?? currentUser.uid;
  return chat.isGroup &&
      (chat.isOwner(uid) || userRoleIsStaff(currentUser.role));
}

String chatRemovalTitle(ChatThreadData chat) {
  if (!chat.isGroup) {
    return 'Delete chat?';
  }

  return currentUserCanDeleteGroupChat(chat) ? 'Delete group?' : 'Leave group?';
}

String chatRemovalBody(ChatThreadData chat) {
  if (!chat.isGroup) {
    return 'This chat will be removed from your list. New messages will bring it back.';
  }

  return currentUserCanDeleteGroupChat(chat)
      ? 'This group will be deleted for all members.'
      : 'You will leave this group and stop receiving messages.';
}

String chatRemovalButtonLabel(ChatThreadData chat) {
  if (!chat.isGroup) {
    return 'Delete chat';
  }

  return currentUserCanDeleteGroupChat(chat) ? 'Delete group' : 'Leave group';
}

String chatRemovalSuccessLabel(ChatThreadData chat) {
  if (!chat.isGroup) {
    return 'Chat deleted.';
  }

  return currentUserCanDeleteGroupChat(chat)
      ? 'Group deleted.'
      : 'You left the group.';
}

String chatRemovalErrorLabel(ChatThreadData chat) {
  if (!chat.isGroup) {
    return 'Could not delete chat.';
  }

  return currentUserCanDeleteGroupChat(chat)
      ? 'Could not delete group.'
      : 'Could not leave group.';
}

Future<bool> confirmAndRemoveChat(
  BuildContext context,
  ChatThreadData chat,
) async {
  final confirmed = await showDialog<bool>(
    context: context,
    builder: (dialogContext) {
      return AlertDialog(
        backgroundColor: panelGlass,
        title: Text(
          chatRemovalTitle(chat),
          style: const TextStyle(
            color: Colors.white,
            fontWeight: FontWeight.w900,
          ),
        ),
        content: Text(
          chatRemovalBody(chat),
          style: const TextStyle(color: Colors.white70),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(dialogContext, false),
            child: const Text('Cancel'),
          ),
          ElevatedButton(
            onPressed: () => Navigator.pop(dialogContext, true),
            style: ElevatedButton.styleFrom(backgroundColor: Colors.redAccent),
            child: Text(
              chatRemovalButtonLabel(chat),
              style: const TextStyle(color: Colors.white),
            ),
          ),
        ],
      );
    },
  );

  if (confirmed != true) {
    return false;
  }

  final successLabel = chatRemovalSuccessLabel(chat);
  final errorLabel = chatRemovalErrorLabel(chat);

  try {
    if (!chat.isGroup) {
      await hideChatForCurrentUser(chat);
    } else if (currentUserCanDeleteGroupChat(chat)) {
      await deleteGroupChat(chat);
    } else {
      await leaveGroupChat(chat);
    }

    await removePinnedChatId(chat.id);

    if (context.mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: blue,
          content: Text(
            successLabel,
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    }
    return true;
  } catch (error) {
    if (context.mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            '$errorLabel $error',
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    }
    return false;
  }
}

class ChatThreadTile extends StatelessWidget {
  final ChatThreadData chat;
  final String currentUid;
  final bool pinned;

  const ChatThreadTile({
    super.key,
    required this.chat,
    required this.currentUid,
    this.pinned = false,
  });

  String? otherUserId() {
    if (chat.isGroup) {
      return null;
    }

    for (final uid in chat.memberIds) {
      if (uid != currentUid && uid.trim().isNotEmpty) {
        return uid;
      }
    }

    return null;
  }

  Widget avatar(FriendUserData? directUser) {
    if (chat.isGroup) {
      final photoUrl = chat.photoUrl.trim();
      if (isNetworkUrl(photoUrl)) {
        return ClipOval(
          child: Image.network(
            photoUrl,
            width: 46,
            height: 46,
            fit: BoxFit.cover,
            errorBuilder: (_, _, _) =>
                const UserAvatarFallback(size: 46, icon: Icons.groups),
          ),
        );
      }

      return const UserAvatarFallback(size: 46, icon: Icons.groups);
    }

    if (directUser != null) {
      return UserAvatarCircle(user: directUser, size: 46);
    }

    return const UserAvatarFallback(size: 46, icon: Icons.person_outline);
  }

  Widget subtitleLine(String subtitle, FriendUserData? directUser) {
    if (!chat.isGroup) {
      return Row(
        children: [
          OnlineStatusBadge(online: directUser?.appearsOnline ?? false),
          if (subtitle.trim().isNotEmpty) ...[
            const SizedBox(width: 8),
            Expanded(
              child: Text(
                subtitle,
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
                style: const TextStyle(color: Colors.white54),
              ),
            ),
          ],
        ],
      );
    }

    return Text(
      subtitle,
      maxLines: 1,
      overflow: TextOverflow.ellipsis,
      style: const TextStyle(color: Colors.white54),
    );
  }

  Widget tile(BuildContext context, FriendUserData? directUser) {
    final title = !chat.isGroup && directUser != null
        ? displayUsername(directUser.username)
        : chat.titleForCurrentUser(currentUid);
    final subtitle = chat.subtitleForCurrentUser(currentUid);

    return InkWell(
      onTap: () {
        Navigator.push(
          context,
          appPageRoute(builder: (_) => ChatConversationScreen(chat: chat)),
        );
      },
      borderRadius: BorderRadius.circular(18),
      child: Container(
        padding: const EdgeInsets.all(14),
        decoration: BoxDecoration(
          color: panelGlass,
          borderRadius: BorderRadius.circular(18),
          border: Border.all(
            color: pinned ? blue.withValues(alpha: 0.75) : Colors.white12,
            width: pinned ? 1.4 : 1,
          ),
        ),
        child: Row(
          children: [
            avatar(directUser),
            const SizedBox(width: 12),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    children: [
                      if (pinned) ...[
                        const Icon(Icons.push_pin, color: blue, size: 14),
                        const SizedBox(width: 4),
                      ],
                      Expanded(
                        child: Text(
                          title,
                          maxLines: 1,
                          overflow: TextOverflow.ellipsis,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 16,
                            fontWeight: FontWeight.w900,
                          ),
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(height: 4),
                  subtitleLine(subtitle, directUser),
                ],
              ),
            ),
            PopupMenuButton<String>(
              color: panel,
              icon: const Icon(Icons.more_horiz, color: Colors.white54),
              onSelected: (value) async {
                if (value == 'remove_chat') {
                  await confirmAndRemoveChat(context, chat);
                }
              },
              itemBuilder: (_) => [
                PopupMenuItem(
                  value: 'remove_chat',
                  child: Row(
                    children: [
                      Icon(
                        chat.isGroup
                            ? (currentUserCanDeleteGroupChat(chat)
                                  ? Icons.delete_outline
                                  : Icons.logout)
                            : Icons.delete_outline,
                        color: Colors.redAccent,
                        size: 20,
                      ),
                      const SizedBox(width: 10),
                      Text(
                        chatRemovalButtonLabel(chat),
                        style: const TextStyle(color: Colors.white),
                      ),
                    ],
                  ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    if (chat.isGroup) {
      return tile(context, null);
    }

    final uid = otherUserId();
    if (uid == null) {
      return tile(context, null);
    }

    final fallbackUser = fallbackChatMember(chat, uid);

    return StreamBuilder<DocumentSnapshot<Map<String, dynamic>>>(
      stream: usersCollection()
          .doc(uid)
          .debugSnapshots('chat: list direct user presence listener'),
      builder: (context, snapshot) {
        final directUser =
            friendUserFromSnapshot(snapshot.data) ?? fallbackUser;
        return tile(context, directUser);
      },
    );
  }
}

