String formatChatMessageTime(int createdAtMillis) {
  if (createdAtMillis <= 0) {
    return '';
  }
  final value = DateTime.fromMillisecondsSinceEpoch(createdAtMillis);
  return '${twoDigits(value.hour)}:${twoDigits(value.minute)}';
}

String chatDateDividerLabel(int createdAtMillis) {
  if (createdAtMillis <= 0) {
    return '';
  }
  final value = DateTime.fromMillisecondsSinceEpoch(createdAtMillis);
  final now = DateTime.now();
  final today = DateTime(now.year, now.month, now.day);
  final messageDay = DateTime(value.year, value.month, value.day);
  final diffDays = today.difference(messageDay).inDays;

  if (diffDays == 0) {
    return trText('Today');
  }
  if (diffDays == 1) {
    return trText('Yesterday');
  }
  return formatShortDate(value);
}

Widget chatDateDivider(String label) {
  return Padding(
    padding: const EdgeInsets.symmetric(vertical: 12),
    child: Row(
      children: [
        const Expanded(child: Divider(color: Colors.white12)),
        Container(
          margin: const EdgeInsets.symmetric(horizontal: 10),
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
          decoration: BoxDecoration(
            color: panelGlass,
            borderRadius: BorderRadius.circular(20),
            border: Border.all(color: Colors.white12),
          ),
          child: Text(
            label,
            style: const TextStyle(
              color: Colors.white54,
              fontSize: 11,
              fontWeight: FontWeight.w800,
            ),
          ),
        ),
        const Expanded(child: Divider(color: Colors.white12)),
      ],
    ),
  );
}

const int chatMessagePageSize = 10;
final Map<String, List<ChatMessageData>> _chatMessageSessionCache = {};
final Map<String, DocumentSnapshot<Map<String, dynamic>>>
_chatOldestMessageDocSessionCache = {};

class ChatConversationScreen extends StatefulWidget {
  final ChatThreadData chat;

  const ChatConversationScreen({super.key, required this.chat});

  @override
  State<ChatConversationScreen> createState() => _ChatConversationScreenState();
}

class _ChatConversationScreenState extends State<ChatConversationScreen> {
  final messageController = TextEditingController();
  final chatScrollController = ScrollController();
  StreamSubscription<QuerySnapshot<Map<String, dynamic>>>?
  _newMessagesSubscription;
  bool isSending = false;
  bool isSharingChatLocation = false;
  bool hasScrolledToLatestMessage = false;
  bool scrollToLatestAfterNextMessage = false;
  int renderedMessageCount = 0;

  // Messages are loaded in pages. The initial page is only the latest 10.
  final List<ChatMessageData> _messages = [];
  DocumentSnapshot<Map<String, dynamic>>? _oldestLoadedDoc;
  bool _isInitialLoadingMessages = true;
  bool _isLoadingOlderMessages = false;
  bool _hasMoreOlderMessages = true;
  bool _paginationInitialized = false;
  bool _initialBottomScrollDone = false;

  @override
  void initState() {
    super.initState();
    chatScrollController.addListener(_onScroll);
    unawaited(_loadInitialMessages());
  }

  @override
  void dispose() {
    _newMessagesSubscription?.cancel();
    chatScrollController.removeListener(_onScroll);
    messageController.dispose();
    chatScrollController.dispose();
    super.dispose();
  }

  void _cacheMessages() {
    _chatMessageSessionCache[widget.chat.id] = List<ChatMessageData>.from(
      _messages,
    );
    final oldest = _oldestLoadedDoc;
    if (oldest != null) {
      _chatOldestMessageDocSessionCache[widget.chat.id] = oldest;
    }
  }

  void _mergeMessages(Iterable<ChatMessageData> incoming) {
    final byId = <String, ChatMessageData>{
      for (final message in _messages) message.id: message,
    };
    for (final message in incoming) {
      if (message.text.trim().isEmpty) {
        continue;
      }
      byId[message.id] = message;
    }
    _messages
      ..clear()
      ..addAll(byId.values);
    _messages.sort((a, b) => a.createdAtMillis.compareTo(b.createdAtMillis));
    _cacheMessages();
  }

  int get _latestLoadedMessageMillis {
    var latest = 0;
    for (final message in _messages) {
      if (message.createdAtMillis > latest) {
        latest = message.createdAtMillis;
      }
    }
    return latest;
  }

  Future<void> _loadInitialMessages() async {
    final cachedMessages = _chatMessageSessionCache[widget.chat.id];
    if (cachedMessages != null) {
      _messages
        ..clear()
        ..addAll(cachedMessages);
      _oldestLoadedDoc = _chatOldestMessageDocSessionCache[widget.chat.id];
      _paginationInitialized = _oldestLoadedDoc != null || _messages.isEmpty;
      _hasMoreOlderMessages = _messages.length >= chatMessagePageSize;
      if (mounted) {
        setState(() => _isInitialLoadingMessages = false);
        scheduleScrollToLatestMessage();
      }
      _startNewMessagesListener();
      return;
    }

    try {
      final snapshot = await latestChatMessagesQuery(
        widget.chat.id,
      ).debugGet(null, 'chat: initial latest messages');

      if (!mounted) {
        return;
      }

      final loaded = snapshot.docs
          .map((doc) => ChatMessageData.fromFirestore(doc))
          .where((message) => message.text.trim().isNotEmpty)
          .toList();
      loaded.sort((a, b) => a.createdAtMillis.compareTo(b.createdAtMillis));

      setState(() {
        _messages
          ..clear()
          ..addAll(loaded);
        _oldestLoadedDoc = snapshot.docs.isEmpty ? null : snapshot.docs.last;
        _hasMoreOlderMessages = snapshot.docs.length >= chatMessagePageSize;
        _paginationInitialized = true;
        _isInitialLoadingMessages = false;
      });
      _cacheMessages();
      scheduleScrollToLatestMessage();
      _startNewMessagesListener();
    } catch (error, stack) {
      debugPrint('Initial chat messages could not load: $error');
      debugPrint('$stack');
      if (mounted) {
        setState(() => _isInitialLoadingMessages = false);
      }
      _startNewMessagesListener();
    }
  }

  void _startNewMessagesListener() {
    _newMessagesSubscription?.cancel();

    final latestMillis = _latestLoadedMessageMillis;
    Query<Map<String, dynamic>> query;
    if (latestMillis > 0) {
      query = chatMessagesCollection(widget.chat.id)
          .where(
            'createdAt',
            isGreaterThan: Timestamp.fromMillisecondsSinceEpoch(latestMillis),
          )
          .orderBy('createdAt')
          .limit(chatMessagePageSize);
    } else {
      query = latestChatMessagesQuery(widget.chat.id);
    }

    _newMessagesSubscription = query
        .debugSnapshots('chat: new messages listener')
        .listen(
          (snapshot) {
            if (!mounted || snapshot.docs.isEmpty) {
              return;
            }

            final shouldFollow = isNearLatestMessage();
            final incoming = snapshot.docs
                .map((doc) => ChatMessageData.fromFirestore(doc))
                .where((message) => message.text.trim().isNotEmpty)
                .toList();

            setState(() => _mergeMessages(incoming));
            if (shouldFollow || scrollToLatestAfterNextMessage) {
              scheduleScrollToLatestMessage(animated: true);
            }
          },
          onError: (Object error, StackTrace stack) {
            debugPrint('New chat messages listener failed: $error');
            debugPrint('$stack');
          },
        );
  }

  void _onScroll() {
    if (!chatScrollController.hasClients || !_initialBottomScrollDone) return;
    final position = chatScrollController.position;
    // Load older messages only after the initial jump to bottom is finished and
    // the user intentionally scrolls near the top.
    if (position.pixels <= 120 &&
        _hasMoreOlderMessages &&
        !_isLoadingOlderMessages &&
        _paginationInitialized) {
      unawaited(_loadOlderMessages());
    }
  }

  Future<void> _loadOlderMessages() async {
    if (_isLoadingOlderMessages || !_hasMoreOlderMessages) return;
    if (_oldestLoadedDoc == null) return;

    final oldMaxExtent = chatScrollController.hasClients
        ? chatScrollController.position.maxScrollExtent
        : 0.0;
    final oldOffset = chatScrollController.hasClients
        ? chatScrollController.position.pixels
        : 0.0;

    setState(() => _isLoadingOlderMessages = true);

    try {
      final snapshot = await chatMessagesCollection(widget.chat.id)
          .orderBy('createdAt', descending: true)
          .startAfterDocument(_oldestLoadedDoc!)
          .limit(chatMessagePageSize)
          .debugGet(null, 'chat: load older messages');

      if (!mounted) return;

      final older = snapshot.docs
          .map((doc) => ChatMessageData.fromFirestore(doc))
          .where((message) => message.text.trim().isNotEmpty)
          .toList()
          .reversed
          .toList();

      setState(() {
        if (older.isNotEmpty) {
          _oldestLoadedDoc = snapshot.docs.last;
          _mergeMessages(older);
        }
        _hasMoreOlderMessages = snapshot.docs.length >= chatMessagePageSize;
        _isLoadingOlderMessages = false;
      });

      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mounted || !chatScrollController.hasClients) {
          return;
        }
        final newMaxExtent = chatScrollController.position.maxScrollExtent;
        final addedHeight = newMaxExtent - oldMaxExtent;
        chatScrollController.jumpTo(oldOffset + addedHeight);
      });
    } catch (error, stack) {
      debugPrint('Older chat messages could not load: $error');
      debugPrint('$stack');
      if (mounted) setState(() => _isLoadingOlderMessages = false);
    }
  }

  bool isNearLatestMessage() {
    if (!chatScrollController.hasClients) {
      return true;
    }

    final position = chatScrollController.position;
    return position.maxScrollExtent - position.pixels < 140;
  }

  void scheduleScrollToLatestMessage({bool animated = false}) {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted || !chatScrollController.hasClients) {
        return;
      }

      final target = chatScrollController.position.maxScrollExtent;
      if (animated && _initialBottomScrollDone) {
        chatScrollController.animateTo(
          target,
          duration: const Duration(milliseconds: 220),
          curve: Curves.easeOut,
        );
      } else {
        chatScrollController.jumpTo(target);
      }
      _initialBottomScrollDone = true;
    });
  }

  void updateChatScrollForMessages(int messageCount) {
    final firstMessageLayout = !hasScrolledToLatestMessage;
    final receivedNewMessage = messageCount > renderedMessageCount;
    final shouldFollowLatest =
        firstMessageLayout ||
        (receivedNewMessage &&
            (scrollToLatestAfterNextMessage || isNearLatestMessage()));

    renderedMessageCount = messageCount;
    if (firstMessageLayout) {
      hasScrolledToLatestMessage = true;
    }
    if (receivedNewMessage) {
      scrollToLatestAfterNextMessage = false;
    }
    if (shouldFollowLatest) {
      scheduleScrollToLatestMessage(animated: !firstMessageLayout);
    }
  }

  Future<void> sendMessage() async {
    final text = messageController.text.trim();

    if (text.isEmpty || isSending) {
      return;
    }

    setState(() => isSending = true);

    try {
      await sendChatMessage(
        chatId: widget.chat.id,
        text: text,
        chat: widget.chat,
      );
      messageController.clear();
      scrollToLatestAfterNextMessage = true;
      scheduleScrollToLatestMessage(animated: true);
    } catch (error) {
      if (!mounted) {
        return;
      }

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Could not send message: $error',
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    } finally {
      if (mounted) {
        setState(() => isSending = false);
      }
    }
  }

  Future<void> shareLiveLocation() async {
    if (isSharingChatLocation) {
      return;
    }

    setState(() => isSharingChatLocation = true);

    try {
      await shareChatLiveLocation(context, widget.chat);
    } catch (error) {
      if (!mounted) {
        return;
      }

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Could not share location: $error',
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    } finally {
      if (mounted) {
        setState(() => isSharingChatLocation = false);
      }
    }
  }

  String? otherUserId(String currentUid) {
    if (widget.chat.isGroup) {
      return null;
    }

    for (final uid in widget.chat.memberIds) {
      if (uid != currentUid && uid.trim().isNotEmpty) {
        return uid;
      }
    }

    return null;
  }

  String otherUsername(String currentUid) {
    for (var index = 0; index < widget.chat.memberIds.length; index++) {
      final uid = widget.chat.memberIds[index];
      if (uid == currentUid) {
        continue;
      }

      if (index < widget.chat.memberUsernames.length) {
        return widget.chat.memberUsernames[index];
      }
    }

    return '';
  }

  void openChatUserProfile(String currentUid) {
    final uid = otherUserId(currentUid);

    if (uid == null) {
      return;
    }

    openUserProfile(
      context,
      uid: uid,
      fallbackUsername: otherUsername(currentUid),
    );
  }

  Future<void> openGroupSettings() async {
    final removed = await Navigator.push<bool>(
      context,
      appPageRoute(builder: (_) => GroupSettingsScreen(chat: widget.chat)),
    );
    if (removed == true && mounted) {
      Navigator.of(context).maybePop();
    }
  }

  Future<void> removeCurrentChat() async {
    final removed = await confirmAndRemoveChat(context, widget.chat);
    if (removed && mounted) {
      Navigator.of(context).maybePop();
    }
  }

  Future<void> showOwnMessageActions(ChatMessageData message) async {
    final action = await showModalBottomSheet<String>(
      context: context,
      backgroundColor: panelGlass,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
      ),
      builder: (context) {
        return SafeArea(
          child: Padding(
            padding: const EdgeInsets.fromLTRB(18, 12, 18, 20),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                ListTile(
                  leading: const Icon(Icons.edit, color: blue),
                  title: const Text(
                    'Edit message',
                    style: TextStyle(
                      color: Colors.white,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                  onTap: () => Navigator.pop(context, 'edit'),
                ),
                ListTile(
                  leading: const Icon(
                    Icons.delete_outline,
                    color: Colors.redAccent,
                  ),
                  title: const Text(
                    'Delete message',
                    style: TextStyle(
                      color: Colors.white,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                  onTap: () => Navigator.pop(context, 'delete'),
                ),
              ],
            ),
          ),
        );
      },
    );

    if (!mounted || action == null) {
      return;
    }

    if (action == 'edit') {
      await showEditMessageDialog(message);
    } else if (action == 'delete') {
      await confirmDeleteMessage(message);
    }
  }

  Future<void> showEditMessageDialog(ChatMessageData message) async {
    final controller = TextEditingController(text: message.text);

    final updatedText = await showDialog<String>(
      context: context,
      builder: (context) {
        return AlertDialog(
          backgroundColor: panelGlass,
          title: const Text(
            'Edit message',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w900),
          ),
          content: TextField(
            controller: controller,
            autofocus: true,
            minLines: 2,
            maxLines: 5,
            keyboardType: TextInputType.multiline,
            textInputAction: TextInputAction.newline,
            style: const TextStyle(color: Colors.white),
            decoration: InputDecoration(
              hintText: trText('Message'),
              hintStyle: const TextStyle(color: Colors.white38),
              filled: true,
              fillColor: Colors.white.withValues(alpha: 0.06),
              border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(16),
                borderSide: const BorderSide(color: Colors.white12),
              ),
              focusedBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(16),
                borderSide: const BorderSide(color: blue),
              ),
            ),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              onPressed: () => Navigator.pop(context, controller.text),
              style: ElevatedButton.styleFrom(backgroundColor: blue),
              child: const Text('Save', style: TextStyle(color: Colors.white)),
            ),
          ],
        );
      },
    );

    controller.dispose();

    if (!mounted ||
        updatedText == null ||
        updatedText.trim() == message.text.trim()) {
      return;
    }

    try {
      await editChatMessage(
        chatId: widget.chat.id,
        message: message,
        text: updatedText,
      );
    } catch (error) {
      if (!mounted) {
        return;
      }

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Could not edit message: $error',
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    }
  }

  Future<void> confirmDeleteMessage(ChatMessageData message) async {
    final shouldDelete = await showDialog<bool>(
      context: context,
      builder: (context) {
        return AlertDialog(
          backgroundColor: panelGlass,
          title: const Text(
            'Delete message?',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w900),
          ),
          content: const Text(
            'This message will be deleted from the chat.',
            style: TextStyle(color: Colors.white70),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(context, false),
              child: const Text('Cancel'),
            ),
            ElevatedButton(
              onPressed: () => Navigator.pop(context, true),
              style: ElevatedButton.styleFrom(
                backgroundColor: Colors.redAccent,
              ),
              child: const Text(
                'Delete',
                style: TextStyle(color: Colors.white),
              ),
            ),
          ],
        );
      },
    );

    if (!mounted || shouldDelete != true) {
      return;
    }

    try {
      await deleteChatMessage(chatId: widget.chat.id, message: message);
    } catch (error) {
      if (!mounted) {
        return;
      }

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Could not delete message: $error',
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w700,
            ),
          ),
        ),
      );
    }
  }

  Widget directChatTitle(
    String currentUid,
    String fallbackTitle,
    String fallbackPhotoUrl,
  ) {
    final uid = otherUserId(currentUid);

    Widget titleContent(FriendUserData? user) {
      final title = user == null
          ? fallbackTitle
          : displayUsername(user.username);

      return InkWell(
        onTap: () => openChatUserProfile(currentUid),
        borderRadius: BorderRadius.circular(14),
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 2, vertical: 5),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              user == null
                  ? ChatTitleAvatar(photoUrl: fallbackPhotoUrl, title: title)
                  : UserAvatarCircle(user: user, size: 34),
              const SizedBox(width: 10),
              Flexible(
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      title,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                        color: Colors.white,
                        fontSize: 16,
                        fontWeight: FontWeight.w900,
                      ),
                    ),
                    const SizedBox(height: 2),
                    OnlineStatusBadge(
                      online: user?.appearsOnline ?? false,
                      dotSize: 6,
                      fontSize: 10,
                    ),
                  ],
                ),
              ),
            ],
          ),
        ),
      );
    }

    if (uid == null) {
      return titleContent(null);
    }

    return StreamBuilder<DocumentSnapshot<Map<String, dynamic>>>(
      stream: usersCollection()
          .doc(uid)
          .debugSnapshots('chat: conversation title user listener'),
      builder: (context, snapshot) {
        return titleContent(friendUserFromSnapshot(snapshot.data));
      },
    );
  }

  Widget groupChatTitle(String title) {
    return InkWell(
      onTap: openGroupSettings,
      borderRadius: BorderRadius.circular(12),
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 2, vertical: 6),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            const Icon(Icons.groups, size: 21),
            const SizedBox(width: 8),
            Flexible(child: Text(title)),
          ],
        ),
      ),
    );
  }

  Widget messageBubble(
    ChatMessageData message,
    String currentUid,
    Map<String, FriendUserData> usersById,
  ) {
    final mine = message.senderUid == currentUid;
    final canModerateMessage =
        widget.chat.isGroup &&
        (userRoleIsStaff(currentUser.role) ||
            widget.chat.ownerUid == currentUid ||
            widget.chat.moderatorIds.contains(currentUid));
    final showSender = !mine && widget.chat.isGroup;
    final sender =
        usersById[message.senderUid] ?? fallbackMessageSender(message);
    final bubble = Container(
      constraints: BoxConstraints(maxWidth: showSender ? 248 : 280),
      margin: const EdgeInsets.only(bottom: 10),
      padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
      decoration: BoxDecoration(
        color: mine ? blue : panel,
        borderRadius: BorderRadius.only(
          topLeft: const Radius.circular(16),
          topRight: const Radius.circular(16),
          bottomLeft: Radius.circular(mine ? 16 : 5),
          bottomRight: Radius.circular(mine ? 5 : 16),
        ),
        border: mine ? null : Border.all(color: Colors.white12),
      ),
      child: Column(
        crossAxisAlignment: mine
            ? CrossAxisAlignment.end
            : CrossAxisAlignment.start,
        children: [
          if (showSender) ...[
            Text(
              displayUsername(sender.username),
              maxLines: 1,
              overflow: TextOverflow.ellipsis,
              style: const TextStyle(
                color: blue,
                fontSize: 12,
                fontWeight: FontWeight.w900,
              ),
            ),
            const SizedBox(height: 4),
          ],
          Text(
            message.text,
            style: const TextStyle(
              color: Colors.white,
              fontWeight: FontWeight.w600,
              height: 1.25,
            ),
          ),
          const SizedBox(height: 5),
          Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              if (message.edited) ...[
                Text(
                  'edited',
                  style: TextStyle(
                    color: Colors.white.withValues(alpha: 0.58),
                    fontSize: 10,
                    fontWeight: FontWeight.w700,
                  ),
                ),
                const SizedBox(width: 6),
              ],
              Text(
                formatChatMessageTime(message.createdAtMillis),
                style: TextStyle(
                  color: Colors.white.withValues(alpha: 0.62),
                  fontSize: 10,
                  fontWeight: FontWeight.w800,
                ),
              ),
            ],
          ),
        ],
      ),
    );
    final content = showSender
        ? ConstrainedBox(
            constraints: const BoxConstraints(maxWidth: 320),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.end,
              children: [
                Padding(
                  padding: const EdgeInsets.only(bottom: 10),
                  child: GestureDetector(
                    onTap: () => openUserProfile(
                      context,
                      uid: sender.uid,
                      fallbackUsername: sender.username,
                    ),
                    child: UserAvatarCircle(user: sender, size: 30),
                  ),
                ),
                const SizedBox(width: 8),
                Flexible(child: bubble),
              ],
            ),
          )
        : bubble;

    return GestureDetector(
      onLongPress: (mine || canModerateMessage)
          ? () => showOwnMessageActions(message)
          : null,
      child: Align(
        alignment: mine ? Alignment.centerRight : Alignment.centerLeft,
        child: content,
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final firebaseUser = FirebaseAuth.instance.currentUser;
    final currentUid = firebaseUser?.uid ?? currentUser.uid;
    final title = widget.chat.titleForCurrentUser(currentUid);
    final chatPhotoUrl = widget.chat.directPhotoUrlForCurrentUser(currentUid);

    return Scaffold(
      backgroundColor: Colors.transparent,
      appBar: AppBar(
        title: widget.chat.isGroup
            ? groupChatTitle(title)
            : directChatTitle(currentUid, title, chatPhotoUrl),
        backgroundColor: Colors.transparent,
        foregroundColor: blue,
        actions: widget.chat.isGroup
            ? [
                IconButton(
                  tooltip: 'Group info',
                  onPressed: openGroupSettings,
                  icon: const Icon(Icons.info_outline),
                ),
                PopupMenuButton<String>(
                  color: panel,
                  icon: const Icon(Icons.more_horiz),
                  onSelected: (value) {
                    if (value == 'remove_chat') {
                      unawaited(removeCurrentChat());
                    }
                  },
                  itemBuilder: (_) => [
                    PopupMenuItem(
                      value: 'remove_chat',
                      child: Row(
                        children: [
                          Icon(
                            currentUserCanDeleteGroupChat(widget.chat)
                                ? Icons.delete_outline
                                : Icons.logout,
                            color: Colors.redAccent,
                            size: 20,
                          ),
                          const SizedBox(width: 10),
                          Text(chatRemovalButtonLabel(widget.chat)),
                        ],
                      ),
                    ),
                  ],
                ),
              ]
            : [
                IconButton(
                  tooltip: 'Open profile',
                  onPressed: () => openChatUserProfile(currentUid),
                  icon: const Icon(Icons.account_circle_outlined),
                ),
                PopupMenuButton<String>(
                  color: panel,
                  icon: const Icon(Icons.more_horiz),
                  onSelected: (value) {
                    if (value == 'remove_chat') {
                      unawaited(removeCurrentChat());
                    }
                  },
                  itemBuilder: (_) => [
                    PopupMenuItem(
                      value: 'remove_chat',
                      child: Row(
                        children: [
                          const Icon(
                            Icons.delete_outline,
                            color: Colors.redAccent,
                            size: 20,
                          ),
                          const SizedBox(width: 10),
                          Text(chatRemovalButtonLabel(widget.chat)),
                        ],
                      ),
                    ),
                  ],
                ),
              ],
      ),
      body: Column(
        children: [
          Expanded(
            child: Builder(
              builder: (context) {
                final messages = List<ChatMessageData>.from(_messages);
                updateChatScrollForMessages(messages.length);

                if (_isInitialLoadingMessages) {
                  return const Center(
                    child: CircularProgressIndicator(color: blue),
                  );
                }

                if (messages.isEmpty) {
                  return const Padding(
                    padding: EdgeInsets.all(20),
                    child: EmptyStateCard(
                      icon: Icons.chat_bubble_outline,
                      title: 'No messages yet',
                      text: 'Send the first message.',
                    ),
                  );
                }

                Widget listWithUsers(Map<String, FriendUserData> usersById) {
                  String previousDateLabel = '';
                  final children = <Widget>[];
                  for (final message in messages) {
                    final dateLabel = chatDateDividerLabel(
                      message.createdAtMillis,
                    );
                    if (dateLabel.isNotEmpty &&
                        dateLabel != previousDateLabel) {
                      children.add(chatDateDivider(dateLabel));
                      previousDateLabel = dateLabel;
                    }
                    children.add(messageBubble(message, currentUid, usersById));
                  }

                  return ListView(
                    controller: chatScrollController,
                    padding: const EdgeInsets.fromLTRB(16, 16, 16, 8),
                    children: [
                      if (_isLoadingOlderMessages)
                        const Padding(
                          padding: EdgeInsets.all(12),
                          child: Center(
                            child: SizedBox(
                              width: 20,
                              height: 20,
                              child: CircularProgressIndicator(
                                strokeWidth: 2,
                                color: blue,
                              ),
                            ),
                          ),
                        ),
                      if (_hasMoreOlderMessages)
                        Padding(
                          padding: const EdgeInsets.only(bottom: 8),
                          child: Center(
                            child: Text(
                              'Scroll up to load older messages',
                              style: TextStyle(
                                color: Colors.white.withValues(alpha: 0.35),
                                fontSize: 11,
                                fontWeight: FontWeight.w700,
                              ),
                            ),
                          ),
                        ),
                      ...children,
                    ],
                  );
                }

                if (!widget.chat.isGroup) {
                  return listWithUsers(const <String, FriendUserData>{});
                }

                return FutureBuilder<List<FriendUserData>>(
                  future: loadChatMembers(widget.chat),
                  builder: (context, usersSnapshot) {
                    final members =
                        usersSnapshot.data ??
                        [
                          for (final uid in widget.chat.memberIds)
                            fallbackChatMember(widget.chat, uid),
                        ];
                    final usersById = <String, FriendUserData>{
                      for (final member in members) member.uid: member,
                    };

                    return listWithUsers(usersById);
                  },
                );
              },
            ),
          ),
          SafeArea(
            top: false,
            child: Container(
              padding: const EdgeInsets.fromLTRB(12, 10, 12, 12),
              decoration: BoxDecoration(
                color: panelGlass,
                border: const Border(top: BorderSide(color: Colors.white12)),
              ),
              child: Row(
                children: [
                  IconButton(
                    tooltip: 'Share location',
                    onPressed: isSharingChatLocation ? null : shareLiveLocation,
                    style: IconButton.styleFrom(foregroundColor: blue),
                    icon: Icon(
                      isSharingChatLocation
                          ? Icons.hourglass_top
                          : Icons.my_location,
                    ),
                  ),
                  const SizedBox(width: 4),
                  Expanded(
                    child: TextField(
                      controller: messageController,
                      minLines: 1,
                      maxLines: 4,
                      keyboardType: TextInputType.multiline,
                      textInputAction: TextInputAction.newline,
                      style: const TextStyle(color: Colors.white),
                      decoration: InputDecoration(
                        hintText: trText('Message'),
                        hintStyle: const TextStyle(color: Colors.white38),
                        filled: true,
                        fillColor: Colors.white.withValues(alpha: 0.06),
                        contentPadding: const EdgeInsets.symmetric(
                          horizontal: 14,
                          vertical: 12,
                        ),
                        border: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(18),
                          borderSide: const BorderSide(color: Colors.white12),
                        ),
                        enabledBorder: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(18),
                          borderSide: const BorderSide(color: Colors.white12),
                        ),
                        focusedBorder: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(18),
                          borderSide: const BorderSide(color: blue),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 8),
                  IconButton.filled(
                    onPressed: isSending ? null : sendMessage,
                    style: IconButton.styleFrom(
                      backgroundColor: blue,
                      foregroundColor: Colors.white,
                    ),
                    icon: Icon(isSending ? Icons.hourglass_top : Icons.send),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }
}

