  Widget actionButton({
    required String label,
    required VoidCallback? onPressed,
    Color color = blue,
    bool outlined = false,
  }) {
    final shape = RoundedRectangleBorder(
      borderRadius: BorderRadius.circular(999),
    );

    if (outlined) {
      return OutlinedButton(
        onPressed: onPressed,
        style: OutlinedButton.styleFrom(
          foregroundColor: color,
          side: BorderSide(color: color.withValues(alpha: 0.65)),
          padding: const EdgeInsets.symmetric(horizontal: 12),
          shape: shape,
        ),
        child: Text(trText(label)),
      );
    }

    return ElevatedButton(
      onPressed: onPressed,
      style: ElevatedButton.styleFrom(
        backgroundColor: color,
        foregroundColor: Colors.white,
        padding: const EdgeInsets.symmetric(horizontal: 12),
        shape: shape,
      ),
      child: Text(trText(label)),
    );
  }

  Widget friendsTab() {
    final firebaseUser = FirebaseAuth.instance.currentUser;

    if (firebaseUser == null) {
      return const EmptyStateCard(
        icon: Icons.group,
        title: 'Log in required',
        text: 'Log in before using friends.',
      );
    }

    return StreamBuilder<List<FriendUserData>>(
      stream: watchCurrentFriendUsers(),
      builder: (context, snapshot) {
        final friends = snapshot.data ?? const <FriendUserData>[];

        if (snapshot.connectionState == ConnectionState.waiting) {
          return const Center(
            child: Padding(
              padding: EdgeInsets.all(24),
              child: CircularProgressIndicator(color: blue),
            ),
          );
        }

        if (friends.isEmpty) {
          return const EmptyStateCard(
            icon: Icons.group_outlined,
            title: 'No friends yet',
            text: 'Use Find Users to send your first friend request.',
          );
        }

        return Column(
          children: [
            for (final user in friends)
              friendUserTile(
                user: user,
                subtitle: user.name,
                onTap: () => openUserProfile(
                  context,
                  uid: user.uid,
                  fallbackUsername: user.username,
                ),
                trailing: actionButton(
                  label: 'Remove',
                  color: Colors.redAccent,
                  outlined: true,
                  onPressed: () => removeFriend(user),
                ),
              ),
          ],
        );
      },
    );
  }

  Widget friendRequestTile({
    required String uid,
    required String username,
    required String name,
    required Widget trailing,
  }) {
    return InkWell(
      onTap: () =>
          openUserProfile(context, uid: uid, fallbackUsername: username),
      borderRadius: BorderRadius.circular(18),
      child: Container(
        margin: const EdgeInsets.only(bottom: 10),
        padding: const EdgeInsets.all(12),
        decoration: BoxDecoration(
          color: panelGlass,
          borderRadius: BorderRadius.circular(18),
          border: Border.all(color: Colors.white12),
        ),
        child: Row(
          children: [
            userAvatar(username: username),
            const SizedBox(width: 12),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    username,
                    style: const TextStyle(
                      color: Colors.white,
                      fontWeight: FontWeight.w900,
                    ),
                  ),
                  const SizedBox(height: 3),
                  Text(
                    name,
                    style: const TextStyle(color: Colors.white54, fontSize: 12),
                  ),
                ],
              ),
            ),
            const SizedBox(width: 10),
            trailing,
          ],
        ),
      ),
    );
  }

  Widget requestsTab() {
    final firebaseUser = FirebaseAuth.instance.currentUser;

    if (firebaseUser == null) {
      return const EmptyStateCard(
        icon: Icons.mark_email_unread_outlined,
        title: 'Log in required',
        text: 'Log in before using friend requests.',
      );
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        const Text(
          'Incoming requests',
          style: TextStyle(
            color: Colors.white,
            fontSize: 18,
            fontWeight: FontWeight.w900,
          ),
        ),
        const SizedBox(height: 10),
        StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
          stream: friendRequestsCollection()
              .where('toUid', isEqualTo: firebaseUser.uid)
              .where('status', isEqualTo: 'pending')
              .debugSnapshots('friends: incoming requests tab listener'),
          builder: (context, snapshot) {
            final requests =
                snapshot.data?.docs
                    .map((doc) => FriendRequestData.fromFirestore(doc))
                    .toList() ??
                const <FriendRequestData>[];

            if (requests.isEmpty) {
              return const EmptyStateCard(
                icon: Icons.inbox_outlined,
                title: 'No incoming requests',
                text: 'Friend invites sent to you will appear here.',
              );
            }

            return Column(
              children: [
                for (final request in requests)
                  friendRequestTile(
                    uid: request.fromUid,
                    username: request.fromUsername,
                    name: request.fromName,
                    trailing: Row(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        actionButton(
                          label: 'Accept',
                          onPressed: () => acceptRequest(request),
                        ),
                        const SizedBox(width: 6),
                        actionButton(
                          label: 'Decline',
                          color: Colors.redAccent,
                          outlined: true,
                          onPressed: () => declineRequest(request),
                        ),
                      ],
                    ),
                  ),
              ],
            );
          },
        ),
        const SizedBox(height: 22),
        const Text(
          'Sent requests',
          style: TextStyle(
            color: Colors.white,
            fontSize: 18,
            fontWeight: FontWeight.w900,
          ),
        ),
        const SizedBox(height: 10),
        StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
          stream: friendRequestsCollection()
              .where('fromUid', isEqualTo: firebaseUser.uid)
              .where('status', isEqualTo: 'pending')
              .debugSnapshots('friends: sent requests tab listener'),
          builder: (context, snapshot) {
            final requests =
                snapshot.data?.docs
                    .map((doc) => FriendRequestData.fromFirestore(doc))
                    .toList() ??
                const <FriendRequestData>[];

            if (requests.isEmpty) {
              return const EmptyStateCard(
                icon: Icons.outbox_outlined,
                title: 'No sent requests',
                text: 'Requests you send will appear here until accepted.',
              );
            }

            return Column(
              children: [
                for (final request in requests)
                  friendRequestTile(
                    uid: request.toUid,
                    username: request.toUsername,
                    name: request.toName,
                    trailing: actionButton(
                      label: 'Cancel',
                      color: Colors.redAccent,
                      outlined: true,
                      onPressed: () => cancelRequest(request),
                    ),
                  ),
              ],
            );
          },
        ),
      ],
    );
  }

  Widget findUsersTab() {
    final firebaseUser = FirebaseAuth.instance.currentUser;

    if (firebaseUser == null) {
      return const EmptyStateCard(
        icon: Icons.person_search,
        title: 'Log in required',
        text: 'Log in before finding friends.',
      );
    }

    return Column(
      children: [
        TextField(
          controller: searchController,
          onChanged: queueUsersSearch,
          style: const TextStyle(
            color: Colors.white,
            fontWeight: FontWeight.w700,
          ),
          decoration: InputDecoration(
            labelText: trText('Search users'),
            hintText: trText('nickname or name'),
            prefixIcon: const Icon(Icons.search, color: blue),
            labelStyle: const TextStyle(color: Colors.white60),
            hintStyle: const TextStyle(color: Colors.white24),
            filled: true,
            fillColor: Colors.white.withValues(alpha: 0.06),
            enabledBorder: OutlineInputBorder(
              borderRadius: BorderRadius.circular(16),
              borderSide: const BorderSide(color: Colors.white12),
            ),
            focusedBorder: OutlineInputBorder(
              borderRadius: BorderRadius.circular(16),
              borderSide: const BorderSide(color: blue, width: 1.4),
            ),
          ),
        ),
        const SizedBox(height: 16),
        if (searchText.length < 2)
          const EmptyStateCard(
            icon: Icons.person_search,
            title: 'Search users',
            text: 'Type at least 2 characters to search.',
          )
        else
          FutureBuilder<List<FriendUserData>>(
            future: usersSearchFuture,
            builder: (context, snapshot) {
              if (usersSearchFuture == null ||
                  snapshot.connectionState == ConnectionState.waiting) {
                return const Center(
                  child: Padding(
                    padding: EdgeInsets.all(24),
                    child: CircularProgressIndicator(color: blue),
                  ),
                );
              }

              if (snapshot.hasError) {
                return EmptyStateCard(
                  icon: Icons.person_search,
                  title: trText('No users found'),
                  text: trText('Try searching by nickname or name.'),
                );
              }

              final users = snapshot.data ?? const <FriendUserData>[];

              if (users.isEmpty) {
                return const EmptyStateCard(
                  icon: Icons.person_search,
                  title: 'No users found',
                  text: 'Try searching by nickname or name.',
                );
              }

              return Column(
                children: [
                  for (final user in users)
                    FutureBuilder<String>(
                      future: friendStatusLabelForUser(
                        firebaseUser.uid,
                        user.uid,
                      ),
                      builder: (context, statusSnapshot) {
                        final status = statusSnapshot.data ?? 'loading';
                        final isFriend = status == 'friends';
                        final incoming = status == 'incoming';
                        final outgoing = status == 'outgoing';

                        return friendUserTile(
                          user: user,
                          subtitle: user.name,
                          onTap: () => openUserProfile(
                            context,
                            uid: user.uid,
                            fallbackUsername: user.username,
                          ),
                          trailing: incoming
                              ? actionButton(
                                  label: 'Accept',
                                  onPressed: () async {
                                    final doc = await friendRequestsCollection()
                                        .doc(
                                          friendRequestIdFor(
                                            user.uid,
                                            firebaseUser.uid,
                                          ),
                                        )
                                        .debugGet();
                                    if (doc.exists) {
                                      await acceptRequest(
                                        FriendRequestData.fromFirestore(doc),
                                      );
                                    }
                                  },
                                )
                              : actionButton(
                                  label: isFriend
                                      ? 'Friends'
                                      : outgoing
                                      ? 'Sent'
                                      : status == 'loading'
                                      ? '...'
                                      : 'Add',
                                  outlined: isFriend || outgoing,
                                  onPressed:
                                      (isFriend ||
                                          outgoing ||
                                          status == 'loading')
                                      ? null
                                      : () => sendRequest(user),
                                ),
                        );
                      },
                    ),
                ],
              );
            },
          ),
      ],
    );
  }

  Future<String> friendStatusLabelForUser(
    String currentUid,
    String otherUid,
  ) async {
    if (await areUsersFriends(currentUid, otherUid)) {
      return 'friends';
    }

    return await pendingRequestStatusBetweenUsers(currentUid, otherUid) ??
        'none';
  }

  @override
  Widget build(BuildContext context) {
    return DefaultTabController(
      length: 3,
      initialIndex: widget.initialTabIndex,
      child: Scaffold(
        backgroundColor: Colors.transparent,
        appBar: AppBar(
          title: const Text('Friends'),
          backgroundColor: Colors.transparent,
          foregroundColor: blue,
          bottom: TabBar(
            indicatorColor: blue,
            labelColor: Colors.white,
            unselectedLabelColor: Colors.white54,
            tabs: [
              Tab(icon: const Icon(Icons.group), text: trText('Friends')),
              Tab(
                icon: const _IncomingFriendRequestTabIcon(),
                text: trText('Requests'),
              ),
              Tab(icon: const Icon(Icons.person_search), text: trText('Find')),
            ],
          ),
        ),
        body: TabBarView(
          children: [
            SingleChildScrollView(
              padding: const EdgeInsets.fromLTRB(20, 18, 20, 28),
              child: friendsTab(),
            ),
            SingleChildScrollView(
              padding: const EdgeInsets.fromLTRB(20, 18, 20, 28),
              child: requestsTab(),
            ),
            SingleChildScrollView(
              padding: const EdgeInsets.fromLTRB(20, 18, 20, 28),
              child: findUsersTab(),
            ),
          ],
        ),
      ),
    );
  }
}

