class _GarageGalleryHeader extends StatefulWidget {
  final GarageCar car;

  const _GarageGalleryHeader({required this.car});

  @override
  State<_GarageGalleryHeader> createState() => _GarageGalleryHeaderState();
}

class _GarageGalleryHeaderState extends State<_GarageGalleryHeader> {
  int currentIndex = 0;

  List<String> get photos => widget.car.galleryPhotos;

  void openGallery(int index) {
    if (photos.isEmpty) {
      return;
    }

    Navigator.push(
      context,
      appPageRoute(
        builder: (_) =>
            GaragePhotoGalleryScreen(car: widget.car, initialIndex: index),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    if (currentIndex >= photos.length) {
      currentIndex = photos.isEmpty ? 0 : photos.length - 1;
    }

    return ClipRRect(
      borderRadius: const BorderRadius.vertical(top: Radius.circular(22)),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          AspectRatio(
            aspectRatio: garagePhotoAspectRatio,
            child: Stack(
              fit: StackFit.expand,
              children: [
                GestureDetector(
                  onTap: () => openGallery(currentIndex),
                  child: photos.isEmpty
                      ? const _GaragePhotoFallback()
                      : garagePhotoImage(
                          photos[currentIndex],
                          fit: BoxFit.cover,
                        ),
                ),
                Container(
                  decoration: BoxDecoration(
                    gradient: LinearGradient(
                      begin: Alignment.topCenter,
                      end: Alignment.bottomCenter,
                      colors: [
                        Colors.transparent,
                        Colors.black.withValues(alpha: 0.72),
                      ],
                    ),
                  ),
                ),
                if (photos.length > 1)
                  Positioned(
                    top: 12,
                    right: 12,
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 9,
                        vertical: 5,
                      ),
                      decoration: BoxDecoration(
                        color: Colors.black.withValues(alpha: 0.65),
                        borderRadius: BorderRadius.circular(999),
                        border: Border.all(color: Colors.white24),
                      ),
                      child: Text(
                        '${currentIndex + 1}/${photos.length}',
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 12,
                          fontWeight: FontWeight.w900,
                        ),
                      ),
                    ),
                  ),
                Positioned(
                  left: 16,
                  right: 16,
                  bottom: 14,
                  child: Align(
                    alignment: Alignment.bottomLeft,
                    child: ConstrainedBox(
                      constraints: const BoxConstraints(maxWidth: 270),
                      child: Text(
                        widget.car.name,
                        maxLines: 1,
                        overflow: TextOverflow.ellipsis,
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 18,
                          fontWeight: FontWeight.w900,
                        ),
                      ),
                    ),
                  ),
                ),
                Positioned.fill(
                  child: Material(
                    color: Colors.transparent,
                    child: InkWell(
                      onTap: () => openGallery(currentIndex),
                      splashColor: Colors.white10,
                      highlightColor: Colors.white.withValues(alpha: 0.04),
                    ),
                  ),
                ),
              ],
            ),
          ),
          if (photos.length > 1)
            Container(
              width: double.infinity,
              padding: const EdgeInsets.fromLTRB(14, 10, 14, 12),
              color: Colors.black,
              child: Row(
                children: [
                  for (var index = 0; index < photos.length; index++) ...[
                    Expanded(
                      child: GestureDetector(
                        onTap: () => setState(() => currentIndex = index),
                        onLongPress: () => openGallery(index),
                        child: AnimatedContainer(
                          duration: const Duration(milliseconds: 160),
                          height: 70,
                          decoration: BoxDecoration(
                            borderRadius: BorderRadius.circular(14),
                            boxShadow: currentIndex == index
                                ? [
                                    BoxShadow(
                                      color: blue.withValues(alpha: 0.36),
                                      blurRadius: 14,
                                      spreadRadius: 1,
                                    ),
                                  ]
                                : null,
                          ),
                          foregroundDecoration: BoxDecoration(
                            borderRadius: BorderRadius.circular(14),
                            border: Border.all(
                              color: currentIndex == index
                                  ? blue
                                  : Colors.white24,
                              width: currentIndex == index ? 2.2 : 1,
                            ),
                          ),
                          clipBehavior: Clip.antiAlias,
                          child: Stack(
                            fit: StackFit.expand,
                            children: [
                              garagePhotoImage(
                                photos[index],
                                fit: BoxFit.cover,
                              ),
                              if (currentIndex == index)
                                Container(
                                  decoration: BoxDecoration(
                                    color: blue.withValues(alpha: 0.16),
                                  ),
                                ),
                            ],
                          ),
                        ),
                      ),
                    ),
                    if (index != photos.length - 1) const SizedBox(width: 8),
                  ],
                ],
              ),
            ),
        ],
      ),
    );
  }
}

class GaragePhotoGalleryScreen extends StatefulWidget {
  final GarageCar car;
  final int initialIndex;

  const GaragePhotoGalleryScreen({
    super.key,
    required this.car,
    required this.initialIndex,
  });

  @override
  State<GaragePhotoGalleryScreen> createState() =>
      _GaragePhotoGalleryScreenState();
}

class _GaragePhotoGalleryScreenState extends State<GaragePhotoGalleryScreen> {
  late final PageController controller;
  late int currentIndex;

  @override
  void initState() {
    super.initState();
    currentIndex = widget.initialIndex.clamp(
      0,
      widget.car.galleryPhotos.length - 1,
    );
    controller = PageController(initialPage: currentIndex);
  }

  @override
  void dispose() {
    controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final photos = widget.car.galleryPhotos;

    return Scaffold(
      backgroundColor: Colors.black,
      appBar: AppBar(
        backgroundColor: Colors.transparent,
        foregroundColor: Colors.white,
        title: Text(
          photos.isEmpty
              ? widget.car.name
              : '${widget.car.name}  ${currentIndex + 1}/${photos.length}',
          style: const TextStyle(
            color: Colors.white,
            fontWeight: FontWeight.w800,
          ),
        ),
      ),
      body: photos.isEmpty
          ? const Center(child: _GaragePhotoFallback())
          : PageView.builder(
              controller: controller,
              itemCount: photos.length,
              onPageChanged: (index) => setState(() => currentIndex = index),
              itemBuilder: (context, index) {
                return InteractiveViewer(
                  minScale: 1,
                  maxScale: 4,
                  child: Center(
                    child: garagePhotoImage(
                      photos[index],
                      width: double.infinity,
                      height: double.infinity,
                      fit: BoxFit.contain,
                    ),
                  ),
                );
              },
            ),
    );
  }
}

