class _GarageCarPhotoState extends State<GarageCarPhoto> {
  final PageController controller = PageController();
  int currentIndex = 0;

  @override
  void dispose() {
    controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final photos = widget.car.galleryPhotos;

    if (photos.isEmpty) {
      return const _GaragePhotoFallback();
    }

    return Stack(
      fit: StackFit.expand,
      children: [
        GestureDetector(
          onTap: () {
            Navigator.push(
              context,
              appPageRoute(
                builder: (_) => GaragePhotoGalleryScreen(
                  car: widget.car,
                  initialIndex: currentIndex,
                ),
              ),
            );
          },
          child: PageView.builder(
            controller: controller,
            itemCount: photos.length,
            onPageChanged: (index) => setState(() => currentIndex = index),
            itemBuilder: (context, index) {
              return garagePhotoImage(photos[index], fit: BoxFit.cover);
            },
          ),
        ),
        if (photos.length > 1)
          Positioned(
            top: 12,
            right: 12,
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 9, vertical: 5),
              decoration: BoxDecoration(
                color: Colors.black.withValues(alpha: 0.65),
                borderRadius: BorderRadius.circular(999),
                border: Border.all(color: Colors.white24),
              ),
              child: Text(
                '${currentIndex + 1}/${photos.length}',
                style: const TextStyle(
                  color: Colors.white,
                  fontSize: 12,
                  fontWeight: FontWeight.w900,
                ),
              ),
            ),
          ),
      ],
    );
  }
}

Widget garagePhotoImage(
  String source, {
  double? width,
  double? height,
  BoxFit fit = BoxFit.cover,
}) {
  if (localFileExists(source)) {
    return Image.file(
      File(source),
      width: width,
      height: height,
      fit: fit,
      errorBuilder: (_, _, _) => const _GaragePhotoFallback(),
    );
  }

  if (isNetworkUrl(source)) {
    return Image.network(
      source,
      width: width,
      height: height,
      fit: fit,
      errorBuilder: (_, _, _) => const _GaragePhotoFallback(),
    );
  }

  return const _GaragePhotoFallback();
}

