class AdminUserData {
  final String uid;
  final String username;
  final String name;
  final String email;
  final UserRole role;
  final bool verified;
  final bool banned;
  final int? bannedUntilMillis;
  final String banReason;
  final List<String> deviceIds;
  final bool deleted;

  const AdminUserData({
    required this.uid,
    required this.username,
    required this.name,
    required this.email,
    required this.role,
    required this.verified,
    required this.banned,
    this.bannedUntilMillis,
    this.banReason = '',
    this.deviceIds = const [],
    required this.deleted,
  });

  bool get banActive {
    return banned &&
        (bannedUntilMillis == null ||
            bannedUntilMillis! > DateTime.now().millisecondsSinceEpoch);
  }

  String get statusLabel {
    if (deleted) {
      return 'Deleted';
    }

    return userBanLabel(banned: banned, bannedUntilMillis: bannedUntilMillis);
  }

  factory AdminUserData.fromFirestore(
    DocumentSnapshot<Map<String, dynamic>> doc,
  ) {
    final data = doc.data() ?? {};
    final bannedUntilMillis = nullableTimestampMillisFromFirebase(
      data['bannedUntil'],
    );
    final deviceIds = uniqueNonEmptyStrings([
      ...stringListFromFirebase(data['deviceIds'], const []),
      stringFromFirebase(data['lastDeviceId'], ''),
      ...stringListFromFirebase(data['knownDeviceIdsAtBan'], const []),
    ]);

    return AdminUserData(
      uid: stringFromFirebase(data['uid'], doc.id),
      username: stringFromFirebase(data['username'], 'ccs_driver'),
      name: stringFromFirebase(data['name'], 'CCS Driver'),
      email: stringFromFirebase(data['email'], ''),
      role: roleFromFirebase(data['role']),
      verified:
          roleFromFirebase(data['role']) == UserRole.admin ||
          data['verified'] == true,
      banned: data['banned'] == true,
      bannedUntilMillis: bannedUntilMillis,
      banReason: userBanReasonFromFirebase(data),
      deviceIds: deviceIds,
      deleted: data['deleted'] == true,
    );
  }
}

class AdminBanInput {
  final int days;
  final String reason;

  const AdminBanInput({required this.days, required this.reason});
}

class AdminVerifiedUsersScreen extends StatelessWidget {
  const AdminVerifiedUsersScreen({super.key});

  Future<void> setVerifiedStatus(
    BuildContext context,
    AdminUserData user,
    bool verified,
  ) async {
    if (currentUser.role != UserRole.admin) {
      showAdminActionError(
        context,
        message: 'Only admins can change verified status',
        error: 'not-admin',
      );
      return;
    }

    try {
      await usersCollection().doc(user.uid).debugSet({
        'verified': verified,
        'verifiedUpdatedByUid': currentUser.uid,
        'verifiedUpdatedBy': currentUser.username,
        'verifiedUpdatedAt': FieldValue.serverTimestamp(),
        'updatedAt': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));

      if (user.uid == currentUser.uid) {
        setCurrentUser(
          AppUser(
            uid: currentUser.uid,
            name: currentUser.name,
            username: currentUser.username,
            email: currentUser.email,
            photoUrl: currentUser.photoUrl,
            bio: currentUser.bio,
            avatarPath: currentUser.avatarPath,
            role: currentUser.role,
            verified: verified || userRoleIsStaff(currentUser.role),
            city: currentUser.city,
            country: currentUser.country,
          ),
        );
      }
    } catch (error) {
      showAdminActionError(
        context,
        message: 'Could not update verified status',
        error: error,
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.transparent,
      appBar: AppBar(
        title: const Text('Verified Users'),
        backgroundColor: Colors.transparent,
        foregroundColor: blue,
      ),
      body: StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
        stream: usersCollection()
            .orderBy('usernameKey')
            .limit(200)
            .debugSnapshots('admin: verified users list listener'),
        builder: (context, snapshot) {
          final users =
              snapshot.data?.docs
                  .map((doc) => AdminUserData.fromFirestore(doc))
                  .where((user) => !user.deleted)
                  .toList() ??
              const <AdminUserData>[];

          return ListView(
            padding: const EdgeInsets.fromLTRB(20, 18, 20, 28),
            children: [
              const Text(
                'Grant verified status',
                style: TextStyle(
                  color: Colors.white,
                  fontSize: 30,
                  fontWeight: FontWeight.w900,
                ),
              ),
              const SizedBox(height: 6),
              const Text(
                'Verified users can create and see verified-only spots.',
                style: TextStyle(color: Colors.white54, height: 1.35),
              ),
              const SizedBox(height: 18),
              if (users.isEmpty)
                const EmptyStateCard(
                  icon: Icons.verified_user,
                  title: 'No users yet',
                  text: 'Users will appear here after they sign in.',
                )
              else
                for (final user in users) ...[
                  Container(
                    padding: const EdgeInsets.all(14),
                    decoration: BoxDecoration(
                      color: panelGlass,
                      borderRadius: BorderRadius.circular(18),
                      border: Border.all(color: Colors.white12),
                    ),
                    child: Row(
                      children: [
                        Container(
                          width: 42,
                          height: 42,
                          decoration: BoxDecoration(
                            color: user.verified
                                ? blue.withValues(alpha: 0.16)
                                : Colors.white.withValues(alpha: 0.06),
                            shape: BoxShape.circle,
                          ),
                          child: Icon(
                            user.verified
                                ? Icons.verified
                                : Icons.person_outline,
                            color: user.verified ? blue : Colors.white54,
                          ),
                        ),
                        const SizedBox(width: 12),
                        Expanded(
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Row(
                                children: [
                                  Flexible(
                                    child: Text(
                                      user.username,
                                      maxLines: 1,
                                      overflow: TextOverflow.ellipsis,
                                      style: const TextStyle(
                                        color: Colors.white,
                                        fontWeight: FontWeight.w900,
                                      ),
                                    ),
                                  ),
                                  if (userRoleIsStaff(user.role)) ...[
                                    const SizedBox(width: 6),
                                    _ProfileRoleBadge(role: user.role),
                                  ],
                                ],
                              ),
                              const SizedBox(height: 3),
                              Text(
                                user.email.isEmpty ? user.name : user.email,
                                maxLines: 1,
                                overflow: TextOverflow.ellipsis,
                                style: const TextStyle(color: Colors.white54),
                              ),
                            ],
                          ),
                        ),
                        Switch(
                          value: user.verified,
                          activeThumbColor: blue,
                          onChanged: user.role == UserRole.admin
                              ? null
                              : (value) =>
                                    setVerifiedStatus(context, user, value),
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(height: 10),
                ],
            ],
          );
        },
      ),
    );
  }
}

class AdminUsersScreen extends StatefulWidget {
  final bool initialBannedOnly;

  const AdminUsersScreen({super.key, this.initialBannedOnly = false});

  @override
  State<AdminUsersScreen> createState() => _AdminUsersScreenState();
}

class _AdminUsersScreenState extends State<AdminUsersScreen> {
  late bool bannedOnly;

  @override
  void initState() {
    super.initState();
    bannedOnly = widget.initialBannedOnly && currentUser.role == UserRole.admin;
  }

  Future<bool> canManageUser(BuildContext context, AdminUserData user) async {
    if (user.uid == currentUser.uid) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'You cannot manage your own account here.',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
          ),
        ),
      );
      return false;
    }

    if (user.role == UserRole.admin) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Admin accounts cannot be managed here.',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
          ),
        ),
      );
      return false;
    }

    if (currentUser.role == UserRole.moderator &&
        user.role == UserRole.moderator) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          backgroundColor: Colors.redAccent,
          content: Text(
            'Moderators cannot manage other moderators.',
            style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
          ),
        ),
      );
      return false;
    }

    return true;
  }

  bool canShowManagementActions(AdminUserData user) {
    if (user.uid == currentUser.uid || user.role == UserRole.admin) {
      return false;
    }

    return currentUser.role != UserRole.moderator ||
        user.role != UserRole.moderator;
  }

  Future<void> setModeratorStatus(
    BuildContext context,
    AdminUserData user,
    bool makeModerator,
  ) async {
    if (currentUser.role != UserRole.admin) {
      showAdminActionError(
        context,
        message: 'Only admins can change roles',
        error: 'not-admin',
      );
      return;
    }

    if (user.uid == currentUser.uid || user.role == UserRole.admin) {
      showAdminActionError(
        context,
        message: 'This role cannot be changed here',
        error: 'protected-user',
      );
      return;
    }

    try {
      await usersCollection().doc(user.uid).debugSet({
        'role': makeModerator ? 'moderator' : 'user',
        'roleUpdatedByUid': currentUser.uid,
        'roleUpdatedBy': currentUser.username,
        'roleUpdatedAt': FieldValue.serverTimestamp(),
        'updatedAt': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            backgroundColor: blue,
            content: Text(
              makeModerator ? 'Moderator assigned.' : 'Moderator removed.',
              style: const TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    } catch (error) {
      showAdminActionError(
        context,
        message: 'Could not update role',
        error: error,
      );
    }
  }

  Future<AdminBanInput?> requestBanInput(
    BuildContext context,
    AdminUserData user,
  ) async {
    final daysController = TextEditingController(text: '7');
    final reasonController = TextEditingController(text: user.banReason);
    String? errorText;
    var isClosing = false;

    final input = await showDialog<AdminBanInput>(
      context: context,
      builder: (dialogContext) {
        return StatefulBuilder(
          builder: (context, setDialogState) {
            Future<void> submit() async {
              if (isClosing) {
                return;
              }

              final days = int.tryParse(daysController.text.trim());
              final reason = reasonController.text.trim();

              if (days == null || days < 1 || days > 3650) {
                setDialogState(
                  () => errorText = 'Enter a valid number of days.',
                );
                return;
              }

              if (reason.isEmpty) {
                setDialogState(() => errorText = 'Reason is required.');
                return;
              }

              FocusManager.instance.primaryFocus?.unfocus();
              setDialogState(() => isClosing = true);
              await Future<void>.delayed(const Duration(milliseconds: 180));

              if (!dialogContext.mounted) {
                return;
              }

              Navigator.pop(
                dialogContext,
                AdminBanInput(days: days, reason: reason),
              );
            }

            return AlertDialog(
              backgroundColor: panelGlass,
              title: Text(trText('Ban user')),
              content: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  TextField(
                    controller: daysController,
                    keyboardType: TextInputType.number,
                    inputFormatters: [FilteringTextInputFormatter.digitsOnly],
                    style: const TextStyle(color: Colors.white),
                    decoration: InputDecoration(
                      labelText: trText('Ban duration (days)'),
                      prefixIcon: const Icon(Icons.event_busy, color: blue),
                    ),
                  ),
                  const SizedBox(height: 14),
                  TextField(
                    controller: reasonController,
                    minLines: 2,
                    maxLines: 4,
                    style: const TextStyle(color: Colors.white),
                    decoration: InputDecoration(
                      labelText: trText('Ban reason'),
                      prefixIcon: const Icon(Icons.report, color: blue),
                    ),
                  ),
                  if (errorText != null) ...[
                    const SizedBox(height: 12),
                    Align(
                      alignment: Alignment.centerLeft,
                      child: Text(
                        trText(errorText!),
                        style: const TextStyle(
                          color: Colors.redAccent,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                    ),
                  ],
                ],
              ),
              actions: [
                TextButton(
                  onPressed: isClosing
                      ? null
                      : () => Navigator.pop(dialogContext),
                  child: Text(trText('Cancel')),
                ),
                TextButton(
                  onPressed: isClosing ? null : () => unawaited(submit()),
                  child: Text(
                    trText(isClosing ? 'Banning user...' : 'Confirm ban'),
                    style: const TextStyle(color: Colors.redAccent),
                  ),
                ),
              ],
            );
          },
        );
      },
    );

    daysController.dispose();
    reasonController.dispose();
    return input;
  }

  Future<void> banUser(BuildContext context, AdminUserData user) async {
    if (!await canManageUser(context, user)) {
      return;
    }

    final input = await requestBanInput(context, user);
    if (input == null) {
      return;
    }

    final bannedUntil = Timestamp.fromDate(
      DateTime.now().add(Duration(days: input.days)),
    );
    final banData = <String, Object?>{
      'banned': true,
      'bannedUntil': bannedUntil,
      'banReason': input.reason,
      'bannedByUid': currentUser.uid,
      'bannedBy': currentUser.username,
      'bannedAt': FieldValue.serverTimestamp(),
      'knownDeviceIdsAtBan': user.deviceIds,
      'updatedAt': FieldValue.serverTimestamp(),
    };

    if (!context.mounted) {
      return;
    }

    final messenger = ScaffoldMessenger.of(context);
    messenger.showSnackBar(
      SnackBar(
        duration: const Duration(seconds: 2),
        backgroundColor: blue,
        content: Text(
          trText('Banning user...'),
          style: const TextStyle(
            color: Colors.white,
            fontWeight: FontWeight.w700,
          ),
        ),
      ),
    );

    try {
      await usersCollection()
          .doc(user.uid)
          .debugSet(banData, SetOptions(merge: true))
          .timeout(const Duration(seconds: 12));

      for (final deviceId in user.deviceIds) {
        await saveDeviceBanForUser(
          deviceId: deviceId,
          user: user,
          bannedUntil: bannedUntil,
          reason: input.reason,
        ).timeout(const Duration(seconds: 12));
      }

      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            backgroundColor: Colors.redAccent,
            content: Text(
              trText('User banned.'),
              style: const TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    } on FirebaseException catch (error) {
      if (error.code == 'permission-denied' &&
          banData.containsKey('banReason')) {
        try {
          final legacyBanData = Map<String, Object?>.from(banData)
            ..remove('banReason')
            ..remove('knownDeviceIdsAtBan');
          await usersCollection()
              .doc(user.uid)
              .debugSet(legacyBanData, SetOptions(merge: true))
              .timeout(const Duration(seconds: 12));

          if (context.mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
                backgroundColor: Colors.redAccent,
                content: Text(
                  '${trText('User banned.')} ${trText('Deploy Firebase Rules to save ban reasons.')}',
                  style: const TextStyle(
                    color: Colors.white,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
            );
          }
          return;
        } catch (fallbackError) {
          showAdminActionError(
            context,
            message: trText('Could not ban user'),
            error: fallbackError,
          );
          return;
        }
      }

      showAdminActionError(
        context,
        message: trText('Could not ban user'),
        error: error,
      );
    } catch (error) {
      showAdminActionError(
        context,
        message: trText('Could not ban user'),
        error: error,
      );
    }
  }

  Future<void> unbanUser(BuildContext context, AdminUserData user) async {
    if (!await canManageUser(context, user)) {
      return;
    }

    try {
      await usersCollection().doc(user.uid).debugSet({
        'banned': false,
        'bannedUntil': FieldValue.delete(),
        'banReason': FieldValue.delete(),
        'knownDeviceIdsAtBan': FieldValue.delete(),
        'unbannedByUid': currentUser.uid,
        'unbannedBy': currentUser.username,
        'unbannedAt': FieldValue.serverTimestamp(),
        'updatedAt': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));

      for (final deviceId in user.deviceIds) {
        final cleanDeviceId = deviceId.trim();
        if (cleanDeviceId.isEmpty) {
          continue;
        }
        await deviceBansCollection().doc(cleanDeviceId).debugSet({
          'banned': false,
          'unbannedByUid': currentUser.uid,
          'unbannedBy': currentUser.username,
          'unbannedAt': FieldValue.serverTimestamp(),
          'updatedAt': FieldValue.serverTimestamp(),
        }, SetOptions(merge: true));
      }

      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            backgroundColor: blue,
            content: Text(
              'User unbanned.',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    } catch (error) {
      showAdminActionError(
        context,
        message: 'Could not unban user',
        error: error,
      );
    }
  }

  Future<void> deleteUser(BuildContext context, AdminUserData user) async {
    if (!await canManageUser(context, user)) {
      return;
    }

    final confirmed = await showDialog<bool>(
      context: context,
      builder: (dialogContext) {
        return AlertDialog(
          backgroundColor: panelGlass,
          title: const Text('Delete user?'),
          content: Text(
            'This will remove ${displayUsername(user.username)} from the users list.',
            style: const TextStyle(color: Colors.white70),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(dialogContext, false),
              child: const Text('Cancel'),
            ),
            TextButton(
              onPressed: () => Navigator.pop(dialogContext, true),
              child: const Text(
                'Delete',
                style: TextStyle(color: Colors.redAccent),
              ),
            ),
          ],
        );
      },
    );

    if (confirmed != true) {
      return;
    }

    try {
      await usersCollection().doc(user.uid).debugSet({
        'deleted': true,
        'banned': true,
        'bannedUntil': null,
        'publicProfile': false,
        'photoUrl': '',
        'avatarPath': null,
        'bio': 'Profile removed.',
        'garage': <Object>[],
        'settings': const UserSettingsData(
          instagram: '',
          tiktok: '',
          telegram: '',
          reviewNotifications: false,
          likeNotifications: false,
          commentNotifications: false,
          newSpotNotifications: false,
          newMessageNotifications: false,
          publicProfile: false,
          showGarage: false,
        ).toFirebase(),
        'deletedByUid': currentUser.uid,
        'deletedBy': currentUser.username,
        'deletedAt': FieldValue.serverTimestamp(),
        'updatedAt': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));

      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            backgroundColor: Colors.redAccent,
            content: Text(
              'User deleted.',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
        );
      }
    } catch (error) {
      showAdminActionError(
        context,
        message: 'Could not delete user',
        error: error,
      );
    }
  }

  void handleUserAction(
    BuildContext context,
    AdminUserData user,
    String action,
  ) {
    switch (action) {
      case 'open':
        openUserProfile(
          context,
          uid: user.uid,
          fallbackUsername: user.username,
        );
        break;
      case 'ban':
        banUser(context, user);
        break;
      case 'unban':
        unbanUser(context, user);
        break;
      case 'make_moderator':
        setModeratorStatus(context, user, true);
        break;
      case 'remove_moderator':
        setModeratorStatus(context, user, false);
        break;
      case 'delete':
        deleteUser(context, user);
        break;
    }
  }

