  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.transparent,
      appBar: AppBar(
        title: const Text('Users'),
        backgroundColor: Colors.transparent,
        foregroundColor: blue,
      ),
      body: StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
        stream: usersCollection()
            .orderBy('usernameKey')
            .limit(200)
            .debugSnapshots('admin: users management list listener'),
        builder: (context, snapshot) {
          final allUsers =
              snapshot.data?.docs
                  .map((doc) => AdminUserData.fromFirestore(doc))
                  .where((user) => !user.deleted)
                  .toList() ??
              const <AdminUserData>[];
          final canUseBannedList = currentUser.role == UserRole.admin;
          final users = bannedOnly
              ? allUsers.where((user) => user.banned).toList()
              : allUsers;

          return ListView(
            padding: const EdgeInsets.fromLTRB(20, 18, 20, 28),
            children: [
              Text(
                bannedOnly ? 'Banned app users' : 'Users',
                style: TextStyle(
                  color: Colors.white,
                  fontSize: 34,
                  fontWeight: FontWeight.w900,
                ),
              ),
              const SizedBox(height: 6),
              Text(
                users.isEmpty
                    ? bannedOnly
                          ? trText('No banned users')
                          : 'No users yet.'
                    : '${users.length} user${users.length == 1 ? '' : 's'} in Firebase.',
                style: const TextStyle(color: Colors.white54, height: 1.35),
              ),
              if (canUseBannedList) ...[
                const SizedBox(height: 16),
                Row(
                  children: [
                    Expanded(
                      child: ChoiceChip(
                        label: Text(trText('All users')),
                        selected: !bannedOnly,
                        showCheckmark: false,
                        selectedColor: blue,
                        backgroundColor: Colors.white.withValues(alpha: 0.07),
                        side: BorderSide(
                          color: !bannedOnly ? blue : Colors.white12,
                        ),
                        labelStyle: TextStyle(
                          color: !bannedOnly ? Colors.white : Colors.white70,
                          fontWeight: FontWeight.w800,
                        ),
                        onSelected: (_) => setState(() => bannedOnly = false),
                      ),
                    ),
                    const SizedBox(width: 10),
                    Expanded(
                      child: ChoiceChip(
                        label: Text(trText('Banned app users')),
                        selected: bannedOnly,
                        showCheckmark: false,
                        selectedColor: Colors.redAccent,
                        backgroundColor: Colors.white.withValues(alpha: 0.07),
                        side: BorderSide(
                          color: bannedOnly ? Colors.redAccent : Colors.white12,
                        ),
                        labelStyle: TextStyle(
                          color: bannedOnly ? Colors.white : Colors.white70,
                          fontWeight: FontWeight.w800,
                        ),
                        onSelected: (_) => setState(() => bannedOnly = true),
                      ),
                    ),
                  ],
                ),
              ],
              const SizedBox(height: 18),
              if (users.isEmpty)
                EmptyStateCard(
                  icon: bannedOnly ? Icons.block : Icons.people_outline,
                  title: bannedOnly ? 'No banned users' : 'No users yet',
                  text: bannedOnly
                      ? 'Banned users will appear here.'
                      : 'Users will appear here after they sign in.',
                )
              else
                for (final user in users) ...[
                  userTile(context, user),
                  const SizedBox(height: 10),
                ],
            ],
          );
        },
      ),
    );
  }
}

enum AdminSpotFilter { pending, edited, approved, rejected, all }

String adminSpotFilterLabel(AdminSpotFilter filter) {
  switch (filter) {
    case AdminSpotFilter.pending:
      return 'Pending';
    case AdminSpotFilter.edited:
      return 'Edited';
    case AdminSpotFilter.approved:
      return 'Approved';
    case AdminSpotFilter.rejected:
      return 'Rejected';
    case AdminSpotFilter.all:
      return 'All';
  }
}

List<CarSpot> adminSpotsForFilter(AdminSpotFilter filter) {
  final spots = switch (filter) {
    AdminSpotFilter.pending =>
      reviewSpots.value
          .where((spot) => spot.status == SpotStatus.pending)
          .toList(),
    AdminSpotFilter.edited =>
      reviewSpots.value
          .where((spot) => spot.status == SpotStatus.edited)
          .toList(),
    AdminSpotFilter.approved =>
      reviewSpots.value
          .where((spot) => spot.status == SpotStatus.approved)
          .toList(),
    AdminSpotFilter.rejected =>
      reviewSpots.value
          .where((spot) => spot.status == SpotStatus.rejected)
          .toList(),
    AdminSpotFilter.all => [...reviewSpots.value],
  };

  int latestAdminSortMillis(CarSpot spot) {
    return spot.updatedAtMillis > 0
        ? spot.updatedAtMillis
        : spot.createdAtMillis;
  }

  spots.sort((first, second) {
    final timeCompare = latestAdminSortMillis(
      second,
    ).compareTo(latestAdminSortMillis(first));
    if (timeCompare != 0) {
      return timeCompare;
    }

    return second.createdAtMillis.compareTo(first.createdAtMillis);
  });

  return spots;
}

int adminSpotCount(AdminSpotFilter filter) {
  return adminSpotsForFilter(filter).length;
}

String adminEmptyTitle(AdminSpotFilter filter) {
  switch (filter) {
    case AdminSpotFilter.pending:
      return 'No pending spots';
    case AdminSpotFilter.edited:
      return 'No edited spots';
    case AdminSpotFilter.approved:
      return 'No approved spots';
    case AdminSpotFilter.rejected:
      return 'No rejected spots';
    case AdminSpotFilter.all:
      return 'No community spots yet';
  }
}

String adminEmptyText(AdminSpotFilter filter) {
  switch (filter) {
    case AdminSpotFilter.pending:
      return 'New user submitted spots will appear here first.';
    case AdminSpotFilter.edited:
      return 'User spot edits will appear here for approval.';
    case AdminSpotFilter.approved:
      return 'Approved spots will appear here after moderation.';
    case AdminSpotFilter.rejected:
      return 'Rejected spots will appear here after moderation.';
    case AdminSpotFilter.all:
      return 'When users submit spots, they will appear in this admin panel.';
  }
}

Future<bool> confirmDeleteSpot(BuildContext context, CarSpot spot) async {
  final confirmed = await showDialog<bool>(
    context: context,
    builder: (dialogContext) {
      return AlertDialog(
        backgroundColor: panelGlass,
        title: const Text('Delete spot?'),
        content: Text(
          'This will remove "${spot.name}" from Firebase.',
          style: const TextStyle(color: Colors.white70),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(dialogContext, false),
            child: const Text('Cancel'),
          ),
          TextButton(
            onPressed: () => Navigator.pop(dialogContext, true),
            child: const Text(
              'Delete',
              style: TextStyle(color: Colors.redAccent),
            ),
          ),
        ],
      );
    },
  );

  return confirmed == true;
}

void showAdminActionError(
  BuildContext context, {
  required String message,
  required Object error,
}) {
  if (!context.mounted) {
    return;
  }

  final code = error is FirebaseException ? error.code : error.toString();

  ScaffoldMessenger.of(context).showSnackBar(
    SnackBar(
      backgroundColor: Colors.redAccent,
      content: Text(
        '$message: $code',
        style: const TextStyle(
          color: Colors.white,
          fontWeight: FontWeight.w700,
        ),
      ),
    ),
  );
}

Future<void> deleteAdminSpot(
  BuildContext context,
  CarSpot spot, {
  bool popAfterDelete = false,
}) async {
  final confirmed = await confirmDeleteSpot(context, spot);

  if (!confirmed) {
    return;
  }

  try {
    await deleteSpotFromFirebase(spot);

    if (!context.mounted) {
      return;
    }

    ScaffoldMessenger.of(context).showSnackBar(
      const SnackBar(
        backgroundColor: Colors.redAccent,
        content: Text(
          'Spot deleted.',
          style: TextStyle(color: Colors.white, fontWeight: FontWeight.w700),
        ),
      ),
    );

    if (popAfterDelete) {
      Navigator.pop(context);
    }
  } catch (error) {
    showAdminActionError(
      context,
      message: 'Could not delete spot',
      error: error,
    );
  }
}

